function headers() {
  return {
    "Content-Type": "application/json",
  };
}

async function api(path, options = {}) {
  const res = await fetch(path, {
    ...options,
    credentials: "same-origin",
    cache: "no-store",
    headers: { ...headers(), ...(options.headers || {}) },
  });
  const json = await res.json();
  if (!res.ok) throw new Error(json.error || tr("apiError"));
  return json;
}

function isSuperAdminUser() {
  return state.user?.realRole === "superadmin" || state.role === "superadmin";
}

function isPlatformMode() {
  return isSuperAdminUser() && !state.user?.activeTenantId && state.role === "superadmin";
}

function isTenantMode() {
  return state.user?.realRole === "superadmin" && Boolean(state.user?.activeTenantId);
}

async function refreshPlatformTenants() {
  if (!isSuperAdminUser()) return [];
  const [result, audit] = await Promise.all([api("/api/platform/tenants"), api("/api/platform/audit-logs").catch(() => ({ auditLogs: [] }))]);
  state.platformTenants = result.tenants || [];
  state.platformAuditLogs = audit.auditLogs || state.platformAuditLogs || [];
  return state.platformTenants;
}

async function load() {
  state.loading = true;
  render();
  try {
    const result = await api("/api/bootstrap");
    state.data = result;
    if (isSuperAdminUser()) {
      state.platformTenants = result.platform?.tenants || state.platformTenants || [];
      state.platformAuditLogs = result.platform?.auditLogs || state.platformAuditLogs || [];
      if (!state.platformTenants.length || !isPlatformMode()) {
        await refreshPlatformTenants().catch((error) => showToast(errorMessage(error)));
      }
    }
    state.lazyLoaded = {};
    state.lazyLoading = {};
    Object.keys(lazyPromises).forEach((key) => delete lazyPromises[key]);
  } catch (error) {
    state.toast = error.message;
  } finally {
    state.loading = false;
    render();
  }
}

async function fetchLazyData(key) {
  if (!state.data || !lazyResources[key]) return [];
  if (state.lazyLoaded[key]) return state.data[key] || [];
  if (lazyPromises[key]) return lazyPromises[key];
  const [path, responseKey] = lazyResources[key];
  state.lazyLoading[key] = true;
  lazyPromises[key] = api(path)
    .then((result) => {
      state.data[key] = result[responseKey] || [];
      state.lazyLoaded[key] = true;
      return state.data[key];
    })
    .catch((error) => {
      showToast(errorMessage(error));
      throw error;
    })
    .finally(() => {
      state.lazyLoading[key] = false;
      delete lazyPromises[key];
    });
  return lazyPromises[key];
}

function ensureDataLoaded(key) {
  if (!state.data || !lazyResources[key]) return true;
  if (state.lazyLoaded[key]) return true;
  if (!state.lazyLoading[key]) {
    state.lazyLoading[key] = true;
    setTimeout(() => {
      fetchLazyData(key)
        .catch(() => {})
        .finally(render);
    }, 0);
  }
  return false;
}

function ensureDataKeys(keys) {
  return keys.map(ensureDataLoaded).every(Boolean);
}

async function loadDataKeys(keys) {
  const missing = keys.filter((key) => !state.lazyLoaded[key]);
  if (!missing.length) return;
  await Promise.all(missing.map((key) => fetchLazyData(key)));
  render();
}

async function refreshDataKey(key) {
  if (!state.data || !lazyResources[key]) return [];
  const [path, responseKey] = lazyResources[key];
  const result = await api(path);
  state.data[key] = result[responseKey] || [];
  state.lazyLoaded[key] = true;
  return state.data[key];
}

async function refreshBootstrapSlice() {
  if (!state.data) return;
  const result = await api("/api/bootstrap");
  state.data.dashboard = result.dashboard;
  state.data.auditLogs = result.auditLogs || [];
}

function backgroundRefresh(keys = [], includeBootstrap = true) {
  const jobs = [...new Set(keys)].map((key) => refreshDataKey(key));
  if (includeBootstrap) jobs.push(refreshBootstrapSlice());
  if (!jobs.length) return;
  Promise.allSettled(jobs).then((results) => {
    const failed = results.find((result) => result.status === "rejected");
    if (failed) showToast(failed.reason ? errorMessage(failed.reason) : tr("refreshFailed"));
    render();
  });
}

async function checkAuth() {
  state.loading = true;
  render();
  try {
    const result = await api("/api/me");
    setUser(result.user);
    await load();
  } catch (_error) {
    state.user = null;
    state.role = null;
    state.userId = null;
    state.loading = false;
    state.authChecked = true;
    render();
  }
}

function setUser(user) {
  const identityChanged = state.userId !== user.id || state.user?.tenantId !== user.tenantId;
  state.user = user;
  state.role = user.role;
  state.userId = user.id;
  if (identityChanged) {
    state.teacherSelfProfile = null;
    state.teacherSelfProfileLoading = false;
    state.teacherSelfProfileLoaded = false;
  }
  state.authChecked = true;
}

