function errorMessage(error) {
  const message = error?.message || "";
  const map = {
    "Student not found": "errorStudentNotFound",
    "Group not found": "errorGroupNotFound",
    "Teacher not found": "errorTeacherNotFound",
    "Teacher has active groups or upcoming lessons; reassign them before archiving": "errorTeacherArchiveBlocked",
    "Username already exists": "errorUsernameExists",
    "Working hours overlap with an existing interval": "errorWorkingHoursOverlap",
    "Restore teacher before enabling portal access": "errorRestoreBeforeAccess",
    "Teacher is inactive": "errorTeacherInactive",
    "Payment not found": "errorPaymentNotFound",
    "Group has students or lessons and cannot be deleted": "errorGroupDeleteBlocked",
    "Group has active members or upcoming lessons": "errorGroupArchiveBlocked",
    "Group is not active": "errorGroupInactive",
    "Group capacity reached": "errorGroupCapacity",
    "Schedule conflicts with an existing group, teacher, or room interval": "errorScheduleConflict",
    "time is invalid": "errorLessonTimeInvalid",
    "date is invalid": "errorLessonDateInvalid",
    "Lesson already exists": "errorLessonDuplicate",
    "Future lesson cannot be completed": "errorFutureLessonAttendance",
    "Cancelled lesson cannot be completed": "errorCancelledLessonAttendance",
    "Admin role is required": "errorForbidden",
    "SuperAdmin role is required": "errorForbidden",
    "Tenant context is required": "errorForbidden",
    Forbidden: "errorForbidden",
    Unauthorized: "errorUnauthorized",
  };
  return map[message] ? tr(map[message]) : message || tr("apiError");
}

