function ensureTeacherSelfProfileLoaded() {
  if (state.teacherSelfProfileLoaded || state.teacherSelfProfileLoading || !state.userId) return;
  state.teacherSelfProfileLoading = true;
  setTimeout(async () => {
    try {
      state.teacherSelfProfile = await api(`/api/teachers/${encodeURIComponent(state.userId)}`);
      state.teacherSelfProfileLoaded = true;
    } catch (error) {
      showToast(errorMessage(error) || tr("profileLoadingError"));
    } finally {
      state.teacherSelfProfileLoading = false;
      render();
    }
  }, 0);
}

