  const groups = details.groups || [];
  const hours = details.workingHours || [];
  const upcoming = details.upcomingLessons || teacherLessons().filter((lesson) => lesson.date >= todayIso()).slice(0, 10);
  const weekdays = i18n[state.lang]?.weekDaysFull || i18n.uz.weekDaysFull;
  const weeklyHours = Number(teacher.weeklyMinutes || 0) / 60;
  const maxWeeklyHours = Number(teacher.maxWeeklyMinutes || 0) / 60;
  return `<div class="teacher-profile-page">
    <section id="profileSettings" class="card teacher-profile-hero"><span class="teacher-profile-avatar">${html(initials(teacher.name))}</span><div><span class="teacher-page-eyebrow">${html(tr("roleTeacher"))}</span><h2>${html(teacher.name || tr("teacher"))}</h2><p>${html([teacher.specialization, tr(teacher.employmentType || "full_time")].filter(Boolean).join(" · "))}</p></div><span class="status ${statusClass(teacher.status || "active")}">${html(tr(teacher.status || "active"))}</span></section>
    <section class="grid stats-grid teacher-profile-stats">${stat("fa-layer-group", teacher.groupsCount ?? groups.length, tr("assignedGroups"), tr("active"), "brand")}${stat("fa-users", teacher.studentsCount ?? teacherStudentCount(), tr("myStudents"), tr("active"), "green")}${stat("fa-clock", weeklyHours.toLocaleString(currentLocale(), { maximumFractionDigits: 1 }), tr("weeklyLoad"), `${maxWeeklyHours.toLocaleString(currentLocale())} ${tr("hoursShort")}`, "blue")}${stat("fa-circle-check", teacher.completedLessons || 0, tr("completedLessons"), tr("completed"), "green")}</section>
    <div class="grid wide-grid teacher-profile-columns"><div class="grid"><section class="card"><div class="card-header"><h2 class="card-title">${html(tr("profileDetails"))}</h2></div><div class="teacher-profile-fields"><div><span>${html(tr("phone"))}</span><strong>${html(teacher.phone || "—")}</strong></div><div><span>Email</span><strong>${html(teacher.email || "—")}</strong></div><div><span>${html(tr("specialization"))}</span><strong>${html(teacher.specialization || "—")}</strong></div><div><span>${html(tr("employmentType"))}</span><strong>${html(tr(teacher.employmentType || "full_time"))}</strong></div><div><span>${html(tr("hiredAt"))}</span><strong>${html(teacher.hiredAt || "—")}</strong></div><div><span>${html(tr("weeklyCapacity"))}</span><strong>${html(`${weeklyHours.toLocaleString(currentLocale(), { maximumFractionDigits: 1 })} / ${maxWeeklyHours.toLocaleString(currentLocale())} ${tr("hoursShort")}`)}</strong></div></div>${teacher.note ? `<div class="teacher-note"><span>${html(tr("note"))}</span><p>${html(teacher.note)}</p></div>` : ""}</section>${passwordSettingsCard()}</div><div class="grid"><section class="card"><div class="card-header"><h2 class="card-title">${html(tr("workingHours"))}</h2></div><div class="teacher-profile-hours">${hours.map((hour) => `<div><strong>${html(weekdays[Number(hour.weekday) % 7] || hour.weekday)}</strong><span>${html(`${hour.startTime} — ${hour.endTime}`)}</span></div>`).join("") || emptyInlineState("fa-clock", tr("noWorkingHours"))}</div></section><section class="card"><div class="card-header"><h2 class="card-title">${html(tr("assignedGroups"))}</h2></div><div class="teacher-profile-groups">${groups.map((group) => `<button type="button" onclick="openGroupDrawer('${jsString(group.id)}')"><span><strong>${html(group.name)}</strong><small>${html([group.subject, group.room].filter(Boolean).join(" · "))}</small></span><b>${html(group.studentsCount || 0)}</b>${faIcon("fa-chevron-right")}</button>`).join("") || emptyInlineState("fa-layer-group", tr("noTeacherGroups"))}</div></section></div></div>
    <section class="card"><div class="card-header"><h2 class="card-title">${html(tr("upcomingLessons"))}</h2><button class="ghost-button" type="button" onclick="setState({ page: 'lessons' })">${html(tr("viewSchedule"))}</button></div>${lessonsTable(upcoming)}</section>
  </div>`;
