function filterRows(rows) {
  const query = state.search.trim().toLowerCase();
  if (!query) return rows;
  return rows.filter((row) => Object.values(row).some((value) => String(value ?? "").toLowerCase().includes(query)));
}

function tableSearchValue(tableId) {
  return state.tableSearch?.[tableId] || "";
}

function tableSortState(tableId) {
  return state.tableSort?.[tableId] || { column: "", direction: "asc" };
}

function setTableSearch(tableId, value) {
  state.tableSearch = { ...(state.tableSearch || {}), [tableId]: value };
  render();
  focusTableSearch(tableId);
}

function focusTableSearch(tableId) {
  if (typeof document === "undefined" || !document.querySelectorAll) return;
  setTimeout(() => {
    const input = Array.from(document.querySelectorAll("[data-table-search]")).find((element) => element.dataset.tableSearch === tableId);
    if (!input) return;
    input.focus();
    if (typeof input.setSelectionRange === "function") {
      const position = input.value.length;
      input.setSelectionRange(position, position);
    }
  }, 0);
}

function setTableSort(tableId, column) {
  const current = tableSortState(tableId);
  const direction = current.column === column && current.direction === "asc" ? "desc" : "asc";
  state.tableSort = { ...(state.tableSort || {}), [tableId]: { column, direction } };
  render();
}

function tableComparableValue(row, column) {
  if (["debt", "monthlyFee", "amount", "balance", "attempts", "studentCount", "groupsCount", "studentsCount", "weeklyMinutes", "workloadPercent"].includes(column)) return Number(row[column] || 0);
  if (column === "date") return new Date(row.createdAt || row.date || 0).getTime();
  return normalizeSearch(row[column] ?? "");
}

function applyTableControls(tableId, rows, columns) {
  const query = normalizeSearch(tableSearchValue(tableId));
  const searchableColumns = columns.filter((column) => !["actions", "action"].includes(column));
  let nextRows = query
    ? rows.filter((row) => searchableColumns.some((column) => normalizeSearch(row[column]).includes(query)))
    : [...rows];
  const sort = tableSortState(tableId);
  if (sort.column && searchableColumns.includes(sort.column)) {
    nextRows = [...nextRows].sort((a, b) => {
      const first = tableComparableValue(a, sort.column);
      const second = tableComparableValue(b, sort.column);
      if (typeof first === "number" && typeof second === "number") return sort.direction === "asc" ? first - second : second - first;
      return sort.direction === "asc" ? String(first).localeCompare(String(second), currentLocale()) : String(second).localeCompare(String(first), currentLocale());
    });
  }
  return nextRows;
}

function recordCountText(count, total) {
  const key = count === total ? "recordsCount" : "filteredRecordsCount";
  return tr(key).replace("{count}", count).replace("{total}", total);
}

function tableToolbar(tableId, count, total) {
  return `<div class="table-toolbar">
    <div class="table-search-field">${faIcon("fa-magnifying-glass")}<input data-table-search="${attr(tableId)}" value="${attr(tableSearchValue(tableId))}" placeholder="${attr(tr("tableSearchPlaceholder"))}" oninput="setTableSearch('${jsString(tableId)}', this.value)" /></div>
    <div class="table-count">${html(recordCountText(count, total))}</div>
  </div>`;
}

function tableHeaderCell(tableId, column, label) {
  if (["actions", "action"].includes(column)) return `<th>${html(label)}</th>`;
  const sort = tableSortState(tableId);
  const active = sort.column === column;
  const icon = active ? (sort.direction === "asc" ? "fa-arrow-up-short-wide" : "fa-arrow-down-wide-short") : "fa-sort";
  const directionLabel = active && sort.direction === "desc" ? tr("sortDescending") : tr("sortAscending");
  return `<th aria-sort="${active ? (sort.direction === "asc" ? "ascending" : "descending") : "none"}"><button class="sort-button" type="button" onclick="setTableSort('${jsString(tableId)}', '${jsString(column)}')" aria-label="${attr(`${label}: ${directionLabel}`)}"><span>${html(label)}</span>${faIcon(icon)}</button></th>`;
}

function tableCell(modalType, row, column) {
  if (column === "actions") return entityActionButtons(modalType, row.id);
  if (modalType === "student" && column === "name") return studentNameButton(row);
  if (modalType === "student" && column === "telegram") return studentTelegramStatus(row);
  if (modalType === "payment" && column === "studentName") return studentNameButton(studentById(row.studentId) || { id: row.studentId, name: row.studentName });
  if (column === "debt" || column === "monthlyFee" || column === "amount") return html(money(row[column]));
  if (column === "type") return html(tr(row[column]));
  if (column === "date") return html(row.createdAt ? new Date(row.createdAt).toLocaleString(currentLocale()) : row.date || "");
  if (column === "status") return `<span class="status ${statusClass(row[column])}">${html(tr(row[column]))}</span>`;
  return html(row[column] || "");
}

function mobileRecordCard(modalType, row, columns, columnLabels) {
  const visibleColumns = columns.filter((column) => !["actions", "action"].includes(column));
  const titleColumn = visibleColumns[0] || "name";
  const detailColumns = visibleColumns.slice(1);
  return `<article class="mobile-record-card">
    <div class="mobile-record-main">
      <div class="mobile-record-title">${tableCell(modalType, row, titleColumn)}</div>
      ${columns.includes("actions") ? entityActionButtons(modalType, row.id) : ""}
    </div>
    <div class="mobile-record-details">
      ${detailColumns.map((column) => `<div class="mobile-record-field"><span>${html(columnLabels[column] || column)}</span><strong>${tableCell(modalType, row, column)}</strong></div>`).join("")}
    </div>
  </article>`;
}

function mobileRecordList(modalType, rows, columns, columnLabels) {
  return `<div class="mobile-record-list">${rows.map((row) => mobileRecordCard(modalType, row, columns, columnLabels)).join("") || emptyInlineState("fa-magnifying-glass", tr("noSearchResults"))}</div>`;
}

function tablePage(title, modalType, columns, rows) {
  const tableId = modalType;
  const columnLabels = {
    name: tr("name"),
    groupName: tr("group"),
    parentName: tr("parent"),
    phone: tr("phone"),
    telegram: tr("telegram"),
    debt: tr("debt"),
    status: tr("status"),
    balance: tr("balance"),
    subject: tr("subject"),
    teacherName: tr("teacher"),
    room: tr("room"),
    monthlyFee: tr("monthlyFee"),
    studentCount: tr("studentCount"),
    date: tr("date"),
    amount: tr("amount"),
    type: tr("type"),
    description: tr("note"),
    time: tr("time"),
    action: tr("action"),
    actions: tr("actions"),
  };
  const visibleRows = applyTableControls(tableId, rows, columns);
  const body =
    !rows.length && modalType === "student"
      ? emptyDataState("fa-users")
      : `${tableToolbar(tableId, visibleRows.length, rows.length)}<div class="table-wrap desktop-table-wrap"><table><thead><tr>${columns.map((c) => tableHeaderCell(tableId, c, columnLabels[c] || c)).join("")}</tr></thead><tbody>
          ${visibleRows.map((row) => `<tr>${columns.map((c) => `<td>${tableCell(modalType, row, c)}</td>`).join("")}</tr>`).join("") || emptyTableRow(columns.length, tr("noSearchResults"))}
        </tbody></table></div>${mobileRecordList(modalType, visibleRows, columns, columnLabels)}`;
  const actions =
    state.role === "admin"
      ? modalType === "student"
        ? `<div class="page-actions">${excelExportButton("/api/export/students")}<button class="primary-button" onclick="openModal('${jsString(modalType)}')">+ ${html(title)}</button></div>`
        : `<button class="primary-button" onclick="openModal('${jsString(modalType)}')">+ ${html(title)}</button>`
      : "";
  return `<div class="card"><div class="card-header"><h2 class="card-title">${html(title)}</h2>${actions}</div>
    ${body}</div>`;
}

function setStudentFilter(kind, value) {
  if (kind === "status") state.studentStatusFilter = value;
  if (kind === "group") state.studentGroupFilter = value;
  if (kind === "telegram") state.studentTelegramFilter = value;
  render();
}

function studentAttendanceCell(student) {
  const rate = Number(student.attendanceRate || 0);
  const total = Number(student.attendanceTotal || 0);
  return `<div class="student-attendance-cell"><strong>${html(`${rate}%`)}</strong><span>${html(`${total} ${tr("attendanceTotal").toLocaleLowerCase(currentLocale())}`)}</span><i><b style="width:${Math.min(Math.max(rate, 0), 100)}%"></b></i></div>`;
}

function studentBalanceCell(student) {
  const balance = Number(student.balance || 0);
  return `<span class="student-balance ${balance < 0 ? "negative" : balance > 0 ? "positive" : ""}">${html(signedMoney(balance))}</span>`;
}

function studentGuardianCell(student) {
  return `<div class="student-guardian-cell"><strong>${html(student.parentName || "—")}</strong><span>${html([tr(student.parentRelationship || "guardian"), student.phone].filter(Boolean).join(" · "))}</span></div>`;
}

function studentActions(student) {
  const archived = student.status === "left";
  return `<div class="row-actions"><button class="student-profile-action" type="button" onclick="openStudentDrawer('${jsString(student.id)}')">${faIcon("fa-user")}<span>${html(tr("profile"))}</span></button><button class="icon-button table-icon-action" type="button" onclick="openEditModal('student', '${jsString(student.id)}')" title="${attr(tr("edit"))}">${faIcon("fa-pen")}</button>${archived ? `<button class="icon-button table-icon-action" type="button" onclick="restoreStudent('${jsString(student.id)}')" title="${attr(tr("restoreStudent"))}">${faIcon("fa-rotate-left")}</button>` : `<button class="icon-button table-icon-action danger" type="button" onclick="openDeleteConfirm('student', '${jsString(student.id)}')" title="${attr(tr("archiveStudent"))}">${faIcon("fa-box-archive")}</button>`}</div>`;
}

function studentsPage() {
  const allStudents = filterRows(state.data.students || []);
  const activeCount = allStudents.filter((student) => student.status === "active").length;
  const frozenCount = allStudents.filter((student) => student.status === "frozen").length;
  const archivedCount = allStudents.filter((student) => student.status === "left").length;
  const connectedCount = allStudents.filter((student) => Boolean(student.telegramChatId)).length;
  let filtered = state.studentStatusFilter === "all" ? allStudents : allStudents.filter((student) => student.status === state.studentStatusFilter);
  if (state.studentGroupFilter !== "all") filtered = filtered.filter((student) => student.groupId === state.studentGroupFilter);
  if (state.studentTelegramFilter !== "all") filtered = filtered.filter((student) => Boolean(student.telegramChatId) === (state.studentTelegramFilter === "connected"));
  const visible = applyTableControls("student", filtered, ["name", "groupName", "parentName", "attendanceRate", "balance", "telegramChatId", "status"]);
  const groupFilterOptions = (state.data.groups || []).map((group) => `<option value="${attr(group.id)}" ${state.studentGroupFilter === group.id ? "selected" : ""}>${html(group.name)}</option>`).join("");
  return `<div class="student-directory">
    <div class="student-summary-grid"><div><span>${html(tr("activeStudents"))}</span><strong>${html(activeCount)}</strong></div><div><span>${html(tr("frozen"))}</span><strong>${html(frozenCount)}</strong></div><div><span>${html(tr("archived"))}</span><strong>${html(archivedCount)}</strong></div><div><span>${html(tr("telegramConnectedCount"))}</span><strong>${html(connectedCount)}</strong></div></div>
    <div class="card"><div class="card-header"><div><h2 class="card-title">${html(tr("studentDirectory"))}</h2><div class="card-subtitle">${html(tr("studentDirectorySubtitle"))}</div></div><div class="page-actions">${excelExportButton("/api/export/students")}<button class="ghost-button" type="button" onclick="openImportStudentsModal()">${faIcon("fa-file-csv")} ${html(tr("importStudents"))}</button><button class="primary-button" type="button" onclick="openModal('student')">${faIcon("fa-plus")} ${html(tr("newStudent"))}</button></div></div>
      <div class="student-filter-bar"><div class="teacher-filter-row"><button class="filter-chip ${state.studentStatusFilter === "all" ? "active" : ""}" onclick="setStudentFilter('status','all')">${html(tr("all"))}</button><button class="filter-chip ${state.studentStatusFilter === "active" ? "active" : ""}" onclick="setStudentFilter('status','active')">${html(tr("active"))}</button><button class="filter-chip ${state.studentStatusFilter === "frozen" ? "active" : ""}" onclick="setStudentFilter('status','frozen')">${html(tr("frozen"))}</button><button class="filter-chip ${state.studentStatusFilter === "left" ? "active" : ""}" onclick="setStudentFilter('status','left')">${html(tr("archived"))}</button></div><div class="student-select-filters"><select aria-label="${attr(tr("group"))}" onchange="setStudentFilter('group', this.value)"><option value="all">${html(tr("all"))}: ${html(tr("groups"))}</option>${groupFilterOptions}</select><select aria-label="${attr(tr("telegram"))}" onchange="setStudentFilter('telegram', this.value)"><option value="all" ${state.studentTelegramFilter === "all" ? "selected" : ""}>${html(tr("all"))}: Telegram</option><option value="connected" ${state.studentTelegramFilter === "connected" ? "selected" : ""}>${html(tr("connected"))}</option><option value="disconnected" ${state.studentTelegramFilter === "disconnected" ? "selected" : ""}>${html(tr("notConnected"))}</option></select></div></div>
      ${!allStudents.length ? emptyDataState("fa-users") : `${tableToolbar("student", visible.length, filtered.length)}<div class="table-wrap desktop-table-wrap"><table><thead><tr>${tableHeaderCell("student", "name", tr("students"))}${tableHeaderCell("student", "groupName", tr("group"))}${tableHeaderCell("student", "parentName", tr("guardianData"))}${tableHeaderCell("student", "attendanceRate", tr("attendanceRate"))}${tableHeaderCell("student", "balance", tr("balance"))}${tableHeaderCell("student", "telegramChatId", tr("telegram"))}${tableHeaderCell("student", "status", tr("status"))}<th>${html(tr("actions"))}</th></tr></thead><tbody>${visible.map((student) => `<tr class="${student.status === "left" ? "student-row-archived" : ""}"><td>${studentNameButton(student)}</td><td>${html(student.groupName || "—")}</td><td>${studentGuardianCell(student)}</td><td>${studentAttendanceCell(student)}</td><td>${studentBalanceCell(student)}</td><td>${studentTelegramStatus(student)}</td><td><span class="status ${statusClass(student.status)}">${html(tr(student.status === "left" ? "archived" : student.status))}</span></td><td>${studentActions(student)}</td></tr>`).join("") || emptyTableRow(8, tr("noSearchResults"))}</tbody></table></div><div class="mobile-record-list">${visible.map((student) => `<article class="mobile-record-card student-mobile-card ${student.status === "left" ? "student-row-archived" : ""}"><div class="mobile-record-main">${studentNameButton(student)}${studentActions(student)}</div><div class="mobile-record-details"><div class="mobile-record-field"><span>${html(tr("group"))}</span><strong>${html(student.groupName || "—")}</strong></div><div class="mobile-record-field"><span>${html(tr("guardianData"))}</span><strong>${studentGuardianCell(student)}</strong></div><div class="mobile-record-field"><span>${html(tr("attendanceRate"))}</span><strong>${studentAttendanceCell(student)}</strong></div><div class="mobile-record-field"><span>${html(tr("balance"))}</span><strong>${studentBalanceCell(student)}</strong></div><div class="mobile-record-field"><span>${html(tr("status"))}</span><strong><span class="status ${statusClass(student.status)}">${html(tr(student.status === "left" ? "archived" : student.status))}</span></strong></div></div></article>`).join("") || emptyInlineState("fa-magnifying-glass", tr("noSearchResults"))}</div>`}
    </div>
  </div>`;
}

function openImportStudentsModal() {
  state.importModal = { saving: false };
  render();
}

function closeImportStudentsModal() {
  if (state.importModal?.saving) return;
  state.importModal = null;
  render();
}

function importStudentsModal() {
  if (!state.importModal) return "";
  const groups = (state.data?.groups || []).filter((group) => groupStatus(group) === "active");
  return `<div class="modal-backdrop" onclick="closeImportStudentsModal()"><form class="modal" onclick="event.stopPropagation()" onsubmit="importStudentsCsv(event)"><div class="modal-header"><h2 class="card-title">${html(tr("importStudentsTitle"))}</h2><button class="icon-button" type="button" onclick="closeImportStudentsModal()">${faIcon("fa-xmark")}</button></div><div class="modal-body"><div class="field"><label>${html(tr("csvData"))}</label><textarea id="studentsCsv" class="csv-import-textarea" rows="10" required></textarea><small>${html(tr("csvFormatHint"))}</small></div><div class="csv-group-reference">${groups.map((group) => `<code>${html(group.id)}</code><span>${html(group.name)}</span>`).join("")}</div></div><div class="modal-footer"><button class="ghost-button" type="button" onclick="closeImportStudentsModal()">${html(tr("cancel"))}</button><button class="primary-button" type="submit" ${state.importModal.saving ? "disabled" : ""}>${html(state.importModal.saving ? tr("saving") : tr("importStudents"))}</button></div></form></div>`;
}

async function importStudentsCsv(event) {
  event.preventDefault();
  if (!state.importModal || state.importModal.saving) return;
  const csv = val("studentsCsv");
  state.importModal.saving = true;
  render();
  try {
    const result = await api("/api/import/students", { method: "POST", body: JSON.stringify({ csv }) });
    state.importModal = null;
    await Promise.all([refreshDataKey("students"), refreshDataKey("groups"), refreshBootstrapSlice()]);
    showToast(formatTemplate("importedCount", { count: result.imported || 0 }));
    render();
  } catch (error) {
    if (state.importModal) state.importModal.saving = false;
    showToast(errorMessage(error));
  }
}

function groupStatus(group) {
  return group.status || (group.active === false ? "archived" : "active");
}

function groupNameButton(group) {
  const color = /^#[0-9a-f]{6}$/i.test(group.color || "") ? group.color : "#111827";
  return `<button class="group-name-button" type="button" onclick="openGroupDrawer('${jsString(group.id)}')"><span class="group-color-dot" style="background:${attr(color)}"></span><span><strong>${html(group.name)}</strong><small>${html([group.subject, group.level].filter(Boolean).join(" · ") || "—")}</small></span>${faIcon("fa-chevron-right")}</button>`;
}

function groupCapacityCell(group) {
  const count = Number(group.studentsCount || 0);
  const capacity = Number(group.capacity || 0);
  const percent = capacity > 0 ? Math.min(Math.round((count / capacity) * 100), 100) : 0;
  return `<div class="group-capacity"><div><strong>${html(capacity > 0 ? `${count} / ${capacity}` : `${count} / ∞`)}</strong><span>${html(capacity > 0 ? `${Math.max(capacity - count, 0)} ${tr("availableSeats").toLocaleLowerCase(currentLocale())}` : tr("unlimited"))}</span></div><i class="${capacity > 0 && count >= capacity ? "full" : ""}"><b style="width:${percent}%"></b></i></div>`;
}

function groupScheduleCell(group) {
  const summary = group.scheduleSummary || "";
  return `<div class="group-schedule-cell"><strong>${html(summary || tr("noSchedules"))}</strong><span>${html(`${Number(group.schedulesCount || 0)} ${tr("scheduleRules").toLocaleLowerCase(currentLocale())}`)}</span></div>`;
}

function groupLessonCell(group) {
  return `<div class="group-lesson-cell"><strong>${html(Number(group.completedLessons || 0))} ${html(tr("completedGroupLessons").toLocaleLowerCase(currentLocale()))}</strong><span>${html(Number(group.plannedLessons || 0))} ${html(tr("plannedLessons").toLocaleLowerCase(currentLocale()))}</span></div>`;
}

function groupActions(group) {
  const archived = groupStatus(group) === "archived";
  const adminActions = state.role === "admin"
    ? `<button class="icon-button table-icon-action" type="button" onclick="openEditModal('group', '${jsString(group.id)}')" title="${attr(tr("edit"))}">${faIcon("fa-pen")}</button>${archived ? `<button class="icon-button table-icon-action" type="button" onclick="restoreGroup('${jsString(group.id)}')" title="${attr(tr("restoreGroup"))}">${faIcon("fa-rotate-left")}</button>` : `<button class="icon-button table-icon-action danger" type="button" onclick="openDeleteConfirm('group', '${jsString(group.id)}')" title="${attr(tr("archiveGroup"))}">${faIcon("fa-box-archive")}</button>`}`
    : "";
  return `<div class="row-actions"><button class="student-profile-action" type="button" onclick="openGroupDrawer('${jsString(group.id)}')">${faIcon("fa-layer-group")}<span>${html(tr("profile"))}</span></button>${adminActions}</div>`;
}

function setGroupFilter(kind, value) {
  if (kind === "status") state.groupStatusFilter = value;
  if (kind === "teacher") state.groupTeacherFilter = value;
  render();
}

function groupsPage() {
  const allGroups = filterRows(state.data.groups || []);
  const activeGroups = allGroups.filter((group) => groupStatus(group) === "active");
  const activeCount = activeGroups.length;
  const totalStudents = activeGroups.reduce((sum, group) => sum + Number(group.studentsCount || 0), 0);
  const fullCount = activeGroups.filter((group) => Number(group.capacity || 0) > 0 && Number(group.studentsCount || 0) >= Number(group.capacity)).length;
  const noScheduleCount = activeGroups.filter((group) => Number(group.schedulesCount || 0) === 0).length;
  let filtered = state.groupStatusFilter === "all" ? allGroups : allGroups.filter((group) => groupStatus(group) === state.groupStatusFilter);
  if (state.groupTeacherFilter !== "all") filtered = filtered.filter((group) => group.teacherId === state.groupTeacherFilter);
  const visible = applyTableControls("group", filtered, ["name", "subject", "level", "teacherName", "studentsCount", "capacity", "scheduleSummary", "completedLessons", "plannedLessons", "monthlyFee", "status"]);
  const teacherFilterOptions = (state.data.teachers || []).filter((teacher) => teacher.status === "active").map((teacher) => `<option value="${attr(teacher.id)}" ${state.groupTeacherFilter === teacher.id ? "selected" : ""}>${html(teacher.name)}</option>`).join("");
  return `<div class="group-directory"><div class="group-summary-grid"><div><span>${html(tr("activeGroupCount"))}</span><strong>${html(activeCount)}</strong></div><div><span>${html(tr("totalGroupStudents"))}</span><strong>${html(totalStudents)}</strong></div><div><span>${html(tr("fullGroups"))}</span><strong>${html(fullCount)}</strong></div><div><span>${html(tr("groupsWithoutSchedule"))}</span><strong>${html(noScheduleCount)}</strong></div></div><div class="card"><div class="card-header"><div><h2 class="card-title">${html(tr("groupDirectory"))}</h2><div class="card-subtitle">${html(tr("groupDirectorySubtitle"))}</div></div><button class="primary-button" type="button" onclick="openModal('group')">${faIcon("fa-plus")} ${html(tr("newGroup"))}</button></div><div class="student-filter-bar"><div class="teacher-filter-row"><button class="filter-chip ${state.groupStatusFilter === "all" ? "active" : ""}" onclick="setGroupFilter('status','all')">${html(tr("all"))}</button><button class="filter-chip ${state.groupStatusFilter === "active" ? "active" : ""}" onclick="setGroupFilter('status','active')">${html(tr("active"))}</button><button class="filter-chip ${state.groupStatusFilter === "draft" ? "active" : ""}" onclick="setGroupFilter('status','draft')">${html(tr("draft"))}</button><button class="filter-chip ${state.groupStatusFilter === "completed" ? "active" : ""}" onclick="setGroupFilter('status','completed')">${html(tr("completed"))}</button><button class="filter-chip ${state.groupStatusFilter === "archived" ? "active" : ""}" onclick="setGroupFilter('status','archived')">${html(tr("archived"))}</button></div><div class="student-select-filters"><select aria-label="${attr(tr("teacher"))}" onchange="setGroupFilter('teacher',this.value)"><option value="all">${html(tr("all"))}: ${html(tr("teachers"))}</option>${teacherFilterOptions}</select></div></div>${!allGroups.length ? emptyDataState("fa-layer-group") : `${tableToolbar("group", visible.length, filtered.length)}<div class="table-wrap desktop-table-wrap"><table><thead><tr>${tableHeaderCell("group", "name", tr("group"))}${tableHeaderCell("group", "teacherName", tr("mainTeacher"))}${tableHeaderCell("group", "studentsCount", tr("occupancy"))}${tableHeaderCell("group", "scheduleSummary", tr("schedule"))}${tableHeaderCell("group", "completedLessons", tr("lessons"))}${tableHeaderCell("group", "monthlyFee", tr("monthlyFee"))}${tableHeaderCell("group", "status", tr("status"))}<th>${html(tr("actions"))}</th></tr></thead><tbody>${visible.map((group) => `<tr class="${groupStatus(group) === "archived" ? "student-row-archived" : ""}"><td>${groupNameButton(group)}</td><td>${html(group.teacherName || "—")}</td><td>${groupCapacityCell(group)}</td><td>${groupScheduleCell(group)}</td><td>${groupLessonCell(group)}</td><td>${html(money(group.monthlyFee || 0))}</td><td><span class="status ${statusClass(groupStatus(group))}">${html(tr(groupStatus(group)))}</span></td><td>${groupActions(group)}</td></tr>`).join("") || emptyTableRow(8, tr("noSearchResults"))}</tbody></table></div><div class="mobile-record-list">${visible.map((group) => `<article class="mobile-record-card group-mobile-card"><div class="mobile-record-main">${groupNameButton(group)}${groupActions(group)}</div><div class="mobile-record-details"><div class="mobile-record-field"><span>${html(tr("mainTeacher"))}</span><strong>${html(group.teacherName || "—")}</strong></div><div class="mobile-record-field"><span>${html(tr("occupancy"))}</span><strong>${groupCapacityCell(group)}</strong></div><div class="mobile-record-field"><span>${html(tr("schedule"))}</span><strong>${groupScheduleCell(group)}</strong></div><div class="mobile-record-field"><span>${html(tr("monthlyFee"))}</span><strong>${html(money(group.monthlyFee || 0))}</strong></div><div class="mobile-record-field"><span>${html(tr("status"))}</span><strong><span class="status ${statusClass(groupStatus(group))}">${html(tr(groupStatus(group)))}</span></strong></div></div></article>`).join("") || emptyInlineState("fa-magnifying-glass", tr("noSearchResults"))}</div>`}</div></div>`;
}

function teacherNameButton(teacher) {
  return `<button class="teacher-name-button" type="button" onclick="openTeacherDrawer('${jsString(teacher.id)}')"><span class="teacher-avatar">${html(initials(teacher.name))}</span><span><strong>${html(teacher.name)}</strong><small>${html(teacher.specialization || tr(teacher.employmentType || "full_time"))}</small></span>${faIcon("fa-chevron-right")}</button>`;
}

function teacherWorkload(teacher) {
  const hours = Number(teacher.weeklyMinutes || 0) / 60;
  const percent = Number(teacher.workloadPercent || 0);
  const stateKey = hours <= 0 ? "workloadEmpty" : percent > 100 ? "workloadHigh" : "workloadNormal";
  return `<div class="teacher-workload"><div><strong>${html(hours.toLocaleString(currentLocale(), { maximumFractionDigits: 1 }))} ${html(tr("hoursShort"))}</strong><span class="status ${percent > 100 ? "danger" : hours > 0 ? "success" : "info"}">${html(tr(stateKey))}</span></div><span class="workload-track"><i style="width:${Math.min(Math.max(percent, 0), 100)}%"></i></span></div>`;
}

function teacherAccessBadge(teacher) {
  const key = !teacher.hasAccess ? "not_granted" : teacher.accessStatus === "active" ? "accessEnabled" : "accessDisabled";
  const style = teacher.hasAccess && teacher.accessStatus === "active" ? "success" : teacher.hasAccess ? "danger" : "info";
  return `<span class="status ${style}">${html(tr(key))}</span>`;
}

function teacherActions(teacher) {
  return `<div class="row-actions"><button class="student-profile-action" type="button" onclick="openTeacherDrawer('${jsString(teacher.id)}')">${faIcon("fa-user")}<span>${html(tr("profile"))}</span></button><button class="icon-button table-icon-action" type="button" onclick="openEditModal('teacher', '${jsString(teacher.id)}')" title="${attr(tr("edit"))}">${faIcon("fa-pen")}</button>${teacher.status === "active" ? `<button class="icon-button table-icon-action danger" type="button" onclick="openDeleteConfirm('teacher', '${jsString(teacher.id)}')" title="${attr(tr("archiveTeacher"))}">${faIcon("fa-box-archive")}</button>` : `<button class="icon-button table-icon-action" type="button" onclick="restoreTeacher('${jsString(teacher.id)}')" title="${attr(tr("restoreTeacher"))}">${faIcon("fa-rotate-left")}</button>`}</div>`;
}

function setTeacherStatusFilter(value) {
  state.teacherStatusFilter = value;
  render();
}

