function taskAssigneeOptions(selected = "") {
  const options = [{ id: state.userId, name: state.user?.name || tr("roleAdmin") }];
  (state.data?.teachers || []).filter((teacher) => teacher.hasAccess && teacher.status === "active").forEach((teacher) => {
    if (!options.some((item) => item.id === teacher.id)) options.push({ id: teacher.id, name: teacher.name });
  });
  return `<option value="">${html(tr("all"))}</option>${options.map((item) => `<option value="${attr(item.id)}" ${selected === item.id ? "selected" : ""}>${html(item.name)}</option>`).join("")}`;
}

function tasksPage() {
  const tasks = filterRows(state.data.tasks || []);
  const openTasks = tasks.filter((task) => task.status === "open");
  const completedTasks = tasks.filter((task) => task.status === "completed");
  return `<div class="operations-page"><div class="operations-summary"><div><span>${html(tr("open"))}</span><strong>${html(openTasks.length)}</strong></div><div><span>${html(tr("completed"))}</span><strong>${html(completedTasks.length)}</strong></div><div><span>${html(tr("high"))}</span><strong>${html(openTasks.filter((task) => task.priority === "high").length)}</strong></div></div><div class="card"><div class="card-header"><div><h2 class="card-title">${html(tr("tasks"))}</h2><div class="card-subtitle">${html(recordCountText(tasks.length, tasks.length))}</div></div>${state.role === "admin" ? `<button class="primary-button" type="button" onclick="openTaskModal()">${faIcon("fa-plus")} ${html(tr("newTask"))}</button>` : ""}</div><div class="task-list">${tasks.map((task) => `<article class="task-card ${task.status === "completed" ? "completed" : ""}"><button class="task-check" type="button" onclick="updateTaskStatus('${jsString(task.id)}','${task.status === "completed" ? "open" : "completed"}')" aria-label="${attr(task.status === "completed" ? tr("reopenTask") : tr("completeTask"))}">${faIcon(task.status === "completed" ? "fa-circle-check" : "fa-circle")}</button><div class="task-copy"><strong>${html(task.title)}</strong><span>${html([task.assigneeName || tr("all"), task.dueAt ? new Date(task.dueAt).toLocaleString(currentLocale()) : ""].filter(Boolean).join(" · "))}</span>${task.note ? `<p>${html(task.note)}</p>` : ""}</div><span class="status ${task.priority === "high" ? "danger" : task.priority === "low" ? "info" : "warning"}">${html(tr(task.priority))}</span>${state.role === "admin" && task.status !== "archived" ? `<button class="icon-button table-icon-action" type="button" onclick="updateTaskStatus('${jsString(task.id)}','archived')" title="${attr(tr("archiveTask"))}">${faIcon("fa-box-archive")}</button>` : ""}</article>`).join("") || emptyDataState("fa-list-check", tr("noTasks"), tr("emptyAddHint"))}</div></div></div>`;
}

function openTaskModal() {
  state.taskModal = { saving: false };
  render();
}

function closeTaskModal() {
  if (state.taskModal?.saving) return;
  state.taskModal = null;
  render();
}

function taskModal() {
  if (!state.taskModal) return "";
  return `<div class="modal-backdrop" onclick="closeTaskModal()"><form class="modal" onclick="event.stopPropagation()" onsubmit="saveTask(event)"><div class="modal-header"><h2 class="card-title">${html(tr("newTask"))}</h2><button class="icon-button" type="button" onclick="closeTaskModal()">${faIcon("fa-xmark")}</button></div><div class="modal-body"><div class="form-grid"><div class="field span-2"><label>${html(tr("name"))}</label><input id="taskTitle" maxlength="200" required /></div><div class="field"><label>${html(tr("priority"))}</label><select id="taskPriority"><option value="normal">${html(tr("normal"))}</option><option value="high">${html(tr("high"))}</option><option value="low">${html(tr("low"))}</option></select></div><div class="field"><label>${html(tr("assignee"))}</label><select id="taskAssignee">${taskAssigneeOptions()}</select></div><div class="field span-2"><label>${html(tr("dueAt"))}</label><input id="taskDueAt" type="datetime-local" /></div><div class="field span-2"><label>${html(tr("note"))}</label><textarea id="taskNote" maxlength="1000"></textarea></div></div></div><div class="modal-footer"><button class="ghost-button" type="button" onclick="closeTaskModal()">${html(tr("cancel"))}</button><button class="primary-button" type="submit" ${state.taskModal.saving ? "disabled" : ""}>${html(state.taskModal.saving ? tr("saving") : tr("save"))}</button></div></form></div>`;
}

async function saveTask(event) {
  event.preventDefault();
  if (!state.taskModal || state.taskModal.saving) return;
  const payload = { title: val("taskTitle"), priority: val("taskPriority"), assigneeUserId: val("taskAssignee"), dueAt: val("taskDueAt"), note: val("taskNote") };
  state.taskModal.saving = true;
  render();
  try {
    await api("/api/tasks", { method: "POST", body: JSON.stringify(payload) });
    state.taskModal = null;
    await refreshDataKey("tasks");
    showToast(tr("createdSuccessfully"));
    render();
  } catch (error) {
    if (state.taskModal) state.taskModal.saving = false;
    showToast(errorMessage(error));
  }
}

async function updateTaskStatus(taskId, status) {
  try {
    await api(`/api/tasks/${encodeURIComponent(taskId)}`, { method: "PATCH", body: JSON.stringify({ status }) });
    await refreshDataKey("tasks");
    showToast(tr("updatedSuccessfully"));
    render();
  } catch (error) {
    showToast(errorMessage(error));
  }
}

const managementSections = [
  ["branches", "branches", "fa-code-branch"],
  ["attendance", "attendanceReasons", "fa-clipboard-check"],
  ["finance", "finance", "fa-coins"],
  ["periods", "financePeriods", "fa-calendar-check"],
  ["subscriptions", "subscriptions", "fa-ticket"],
  ["roles", "roles", "fa-shield-halved"],
];

function setManagementSection(section) {
  state.managementSection = section;
  render();
}

function managementPage() {
  return `<div class="operations-page"><div class="card operations-header"><div><h2 class="card-title">${html(tr("operationsCenter"))}</h2><div class="card-subtitle">${html(tr("operationsSubtitle"))}</div></div><div class="operations-tabs">${managementSections.map(([section, label, icon]) => `<button type="button" class="filter-chip ${state.managementSection === section ? "active" : ""}" onclick="setManagementSection('${section}')">${faIcon(icon)} ${html(tr(label))}</button>`).join("")}</div></div>${managementSectionBody()}</div>`;
}

function managementSectionBody() {
  if (state.managementSection === "attendance") return attendanceReasonsManagement();
  if (state.managementSection === "finance") return financeDictionariesManagement();
  if (state.managementSection === "periods") return financePeriodsManagement();
  if (state.managementSection === "subscriptions") return subscriptionsManagement();
  if (state.managementSection === "roles") return rolesManagement();
  return branchesManagement();
}

function branchesManagement() {
  const rows = state.data.branches || [];
  return `<div class="grid wide-grid"><div class="card"><div class="card-header"><h2 class="card-title">${html(tr("branches"))}</h2></div><div class="management-list">${rows.map((branch) => `<div class="management-row"><span>${faIcon("fa-building")}<strong>${html(branch.name)}</strong></span><span class="status ${statusClass(branch.status)}">${html(branch.isMain ? tr("mainBranch") : tr(branch.status))}</span></div>`).join("") || emptyInlineState("fa-building", tr("noData"))}</div></div><form class="card management-form" onsubmit="createBranch(event)"><h2 class="card-title">${html(tr("newBranch"))}</h2><div class="field"><label>${html(tr("branchName"))}</label><input id="branchName" maxlength="120" required /></div><div class="field"><label>${html(tr("status"))}</label><select id="branchStatus"><option value="active">${html(tr("active"))}</option><option value="inactive">${html(tr("inactive"))}</option></select></div><button class="primary-button" type="submit" ${state.managementSaving ? "disabled" : ""}>${html(tr("save"))}</button></form></div>`;
}

async function createBranch(event) {
  event.preventDefault();
  await managementMutation("/api/branches", { name: val("branchName"), status: val("branchStatus") }, "branches");
}

function attendanceReasonsManagement() {
  const rows = state.data.attendanceReasonsAdmin || [];
  return `<div class="grid wide-grid"><div class="card"><div class="card-header"><h2 class="card-title">${html(tr("attendanceReasons"))}</h2></div><div class="management-list">${rows.map((reason) => `<div class="management-row"><span><strong>${html(reason.name)}</strong><small>${html(reason.code)} · ${html(tr(reason.attendanceStatus))}</small></span><span>${html(`${reason.chargePercent}% / ${reason.consumePercent}%`)}</span><button class="ghost-button" type="button" onclick="toggleAttendanceReason('${jsString(reason.id)}', ${reason.isActive ? "false" : "true"})" ${reason.isSystem && reason.isActive ? "disabled" : ""}>${html(reason.isActive ? tr("active") : tr("inactive"))}</button></div>`).join("")}</div></div><form class="card management-form" onsubmit="createAttendanceReason(event)"><h2 class="card-title">${html(tr("newAttendanceReason"))}</h2><div class="form-grid"><div class="field"><label>${html(tr("reasonCode"))}</label><input id="attendanceReasonCode" pattern="[a-z][a-z0-9_]{1,39}" required /></div><div class="field"><label>${html(tr("name"))}</label><input id="attendanceReasonName" required /></div><div class="field"><label>${html(tr("status"))}</label><select id="attendanceReasonStatus">${["present","absent","late","excused"].map((item) => `<option value="${item}">${html(tr(item))}</option>`).join("")}</select></div><div class="field"><label>${html(tr("chargePercent"))}</label><input id="attendanceChargePercent" type="number" min="0" max="100" value="100" required /></div><div class="field"><label>${html(tr("consumePercent"))}</label><input id="attendanceConsumePercent" type="number" min="0" max="100" value="100" required /></div></div><button class="primary-button" type="submit" ${state.managementSaving ? "disabled" : ""}>${html(tr("save"))}</button></form></div>`;
}

async function createAttendanceReason(event) {
  event.preventDefault();
  await managementMutation("/api/attendance-reasons", { code: val("attendanceReasonCode"), name: val("attendanceReasonName"), attendanceStatus: val("attendanceReasonStatus"), chargePercent: Number(val("attendanceChargePercent")), consumePercent: Number(val("attendanceConsumePercent")) }, "attendanceReasonsAdmin");
}

async function toggleAttendanceReason(reasonId, isActive) {
  await managementMutation(`/api/attendance-reasons/${encodeURIComponent(reasonId)}`, { isActive }, "attendanceReasonsAdmin", "PATCH");
}

function financeDictionariesManagement() {
  const accounts = state.data.financeAccounts || [];
  const categories = state.data.financeCategories || [];
  return `<div class="grid wide-grid"><div class="card"><div class="card-header"><h2 class="card-title">${html(tr("financeAccounts"))}</h2></div><div class="management-list">${accounts.map((row) => `<div class="management-row"><strong>${html(row.name)}</strong><span class="status ${statusClass(row.status)}">${html(tr(row.type))}</span></div>`).join("")}</div><form class="management-inline-form" onsubmit="createFinanceAccount(event)"><input id="financeAccountName" placeholder="${attr(tr("accountName"))}" required /><select id="financeAccountType">${["cash","bank","card","online"].map((item) => `<option value="${item}">${html(tr(item))}</option>`).join("")}</select><button class="primary-button" type="submit">${faIcon("fa-plus")} ${html(tr("newFinanceAccount"))}</button></form></div><div class="card"><div class="card-header"><h2 class="card-title">${html(tr("financeCategories"))}</h2></div><div class="management-list">${categories.map((row) => `<div class="management-row"><strong>${html(row.name)}</strong><span class="status info">${html(tr(row.kind))}</span></div>`).join("")}</div><form class="management-inline-form" onsubmit="createFinanceCategory(event)"><input id="financeCategoryName" placeholder="${attr(tr("name"))}" required /><select id="financeCategoryKind">${["income","expense","adjustment"].map((item) => `<option value="${item}">${html(tr(item))}</option>`).join("")}</select><button class="primary-button" type="submit">${faIcon("fa-plus")} ${html(tr("newFinanceCategory"))}</button></form></div></div>`;
}

async function createFinanceAccount(event) {
  event.preventDefault();
  await managementMutation("/api/finance/accounts", { name: val("financeAccountName"), type: val("financeAccountType") }, "financeAccounts");
}

async function createFinanceCategory(event) {
  event.preventDefault();
  await managementMutation("/api/finance/categories", { name: val("financeCategoryName"), kind: val("financeCategoryKind") }, "financeCategories");
}

function financePeriodsManagement() {
  const periods = state.data.financePeriods || [];
  return `<div class="grid wide-grid"><div class="card"><div class="card-header"><h2 class="card-title">${html(tr("financePeriods"))}</h2></div><div class="management-list">${periods.map((period) => `<div class="management-row"><span><strong>${html(period.label)}</strong><small>${html(period.startDate)} — ${html(period.endDate)}</small></span><span class="status ${period.status === "closed" ? "danger" : "success"}">${html(tr(period.status))}</span><button class="ghost-button" type="button" onclick="changeFinancePeriod('${jsString(period.id)}','${period.status === "closed" ? "reopen" : "close"}')">${html(tr(period.status === "closed" ? "reopenPeriod" : "closePeriod"))}</button></div>`).join("") || emptyInlineState("fa-calendar", tr("noData"))}</div></div><form class="card management-form" onsubmit="createFinancePeriod(event)"><h2 class="card-title">${html(tr("newFinancePeriod"))}</h2><div class="field"><label>${html(tr("periodLabel"))}</label><input id="financePeriodLabel" required /></div><div class="form-grid"><div class="field"><label>${html(tr("startDate"))}</label><input id="financePeriodStart" type="date" required /></div><div class="field"><label>${html(tr("endDate"))}</label><input id="financePeriodEnd" type="date" required /></div></div><div class="field"><label>${html(tr("branches"))}</label><select id="financePeriodBranch"><option value="">${html(tr("all"))}</option>${(state.data.branches || []).map((branch) => `<option value="${attr(branch.id)}">${html(branch.name)}</option>`).join("")}</select></div><button class="primary-button" type="submit">${html(tr("save"))}</button></form></div>`;
}

async function createFinancePeriod(event) {
  event.preventDefault();
  await managementMutation("/api/finance/periods", { label: val("financePeriodLabel"), startDate: val("financePeriodStart"), endDate: val("financePeriodEnd"), branchId: val("financePeriodBranch") }, "financePeriods");
}

async function changeFinancePeriod(periodId, operation) {
  const reason = window.prompt(tr("operationReasonPrompt"), "");
  if (!String(reason || "").trim()) return;
  await managementMutation(`/api/finance/periods/${encodeURIComponent(periodId)}/${operation}`, { reason: String(reason).trim() }, "financePeriods");
}

function subscriptionsManagement() {
  const rows = state.data.subscriptions || [];
  return `<div class="card"><div class="card-header"><div><h2 class="card-title">${html(tr("subscriptionsManagement"))}</h2><div class="card-subtitle">${html(recordCountText(rows.length, rows.length))}</div></div><button class="primary-button" type="button" onclick="openSubscriptionModal()">${faIcon("fa-plus")} ${html(tr("newSubscription"))}</button></div><div class="management-list">${rows.map((row) => `<div class="management-row"><span><strong>${html(row.studentName)} · ${html(row.name)}</strong><small>${html(row.groupName || "")} · ${html(row.startDate)}${row.endDate ? ` — ${html(row.endDate)}` : ""}</small></span><span>${html(`${row.lessonsUsed}/${row.lessonsTotal || "∞"}`)}</span><strong>${html(money(row.amount))}</strong><span class="status ${statusClass(row.status)}">${html(tr(row.status))}</span></div>`).join("") || emptyInlineState("fa-ticket", tr("noSubscriptions"))}</div></div>`;
}

function rolesManagement() {
  const rows = state.data.roles || [];
  return `<div class="card"><div class="card-header"><h2 class="card-title">${html(tr("roles"))}</h2></div><div class="management-list">${rows.map((role) => `<div class="management-row"><span>${faIcon("fa-shield-halved")}<strong>${html(role.name)}</strong><small>${html(role.code)}</small></span><span>${html(`${tr("rank")}: ${role.rank}`)}</span><span class="status info">${html(role.interface)}</span>${role.isSystem ? `<span class="status warning">${html(tr("systemRole"))}</span>` : ""}</div>`).join("") || emptyInlineState("fa-shield", tr("noData"))}</div></div>`;
}

async function managementMutation(path, payload, refreshKey, method = "POST") {
  if (state.managementSaving) return;
  state.managementSaving = true;
  render();
  try {
    await api(path, { method, body: JSON.stringify(payload) });
    await refreshDataKey(refreshKey);
    state.managementSaving = false;
    showToast(method === "POST" ? tr("createdSuccessfully") : tr("updatedSuccessfully"));
    render();
  } catch (error) {
    state.managementSaving = false;
    showToast(errorMessage(error));
    render();
  }
}

function openSubscriptionModal(studentId = "") {
  state.subscriptionModal = { studentId, saving: false };
  render();
}

function closeSubscriptionModal() {
  if (state.subscriptionModal?.saving) return;
  state.subscriptionModal = null;
  render();
}

function subscriptionModal() {
  if (!state.subscriptionModal) return "";
  return `<div class="modal-backdrop" onclick="closeSubscriptionModal()"><form class="modal" onclick="event.stopPropagation()" onsubmit="saveSubscription(event)"><div class="modal-header"><h2 class="card-title">${html(tr("newSubscription"))}</h2><button class="icon-button" type="button" onclick="closeSubscriptionModal()">${faIcon("fa-xmark")}</button></div><div class="modal-body"><div class="form-grid"><div class="field"><label>${html(tr("students"))}</label><select id="subscriptionStudent" required>${(state.data.students || []).filter((student) => student.status !== "left").map((student) => `<option value="${attr(student.id)}" ${state.subscriptionModal.studentId === student.id ? "selected" : ""}>${html(student.name)}</option>`).join("")}</select></div><div class="field"><label>${html(tr("group"))}</label><select id="subscriptionGroup"><option value="">${html(tr("currentGroup"))}</option>${(state.data.groups || []).filter((group) => groupStatus(group) === "active").map((group) => `<option value="${attr(group.id)}">${html(group.name)}</option>`).join("")}</select></div><div class="field span-2"><label>${html(tr("subscriptionName"))}</label><input id="subscriptionName" value="${attr(tr("subscriptions"))}" required /></div><div class="field"><label>${html(tr("startDate"))}</label><input id="subscriptionStart" type="date" value="${attr(todayIso())}" required /></div><div class="field"><label>${html(tr("endDate"))}</label><input id="subscriptionEnd" type="date" /></div><div class="field"><label>${html(tr("lessonsTotal"))}</label><input id="subscriptionLessonsTotal" type="number" min="0" value="0" required /></div><div class="field"><label>${html(tr("lessonsUsed"))}</label><input id="subscriptionLessonsUsed" type="number" min="0" value="0" required /></div><div class="field span-2"><label>${html(tr("amount"))}</label><input id="subscriptionAmount" type="number" min="0" value="0" required /></div></div></div><div class="modal-footer"><button class="ghost-button" type="button" onclick="closeSubscriptionModal()">${html(tr("cancel"))}</button><button class="primary-button" type="submit" ${state.subscriptionModal.saving ? "disabled" : ""}>${html(state.subscriptionModal.saving ? tr("saving") : tr("save"))}</button></div></form></div>`;
}

async function saveSubscription(event) {
  event.preventDefault();
  if (!state.subscriptionModal || state.subscriptionModal.saving) return;
  const payload = { studentId: val("subscriptionStudent"), groupId: val("subscriptionGroup"), name: val("subscriptionName"), startDate: val("subscriptionStart"), endDate: val("subscriptionEnd"), lessonsTotal: Number(val("subscriptionLessonsTotal")), lessonsUsed: Number(val("subscriptionLessonsUsed")), amount: Number(val("subscriptionAmount")) };
  const studentId = payload.studentId;
  state.subscriptionModal.saving = true;
  render();
  try {
    await api("/api/subscriptions", { method: "POST", body: JSON.stringify(payload) });
    state.subscriptionModal = null;
    if (state.lazyLoaded.subscriptions) await refreshDataKey("subscriptions");
    if (state.drawer?.studentId === studentId) await refreshStudentDrawer();
    showToast(tr("createdSuccessfully"));
    render();
  } catch (error) {
    if (state.subscriptionModal) state.subscriptionModal.saving = false;
    showToast(errorMessage(error));
  }
}

async function refreshStudentDrawer() {
  if (!state.drawer) return;
  const studentId = state.drawer.studentId;
  const tab = state.drawer.tab;
  const result = await api(`/api/students/${encodeURIComponent(studentId)}/profile`);
  if (!state.drawer || state.drawer.studentId !== studentId) return;
  Object.assign(state.drawer, result, { tab, loading: false, saving: false, subscriptions: result.subscriptions || [], recentPayments: result.recentPayments || [] });
}

function ledgerAmount(transaction) {
  if (transaction.signedAmount !== undefined) return Number(transaction.signedAmount || 0);
  return Number(transaction.amount || 0) * (["payment", "discount"].includes(transaction.type) ? 1 : -1);
}

function transactionBadge(transaction) {
  return `<span class="ledger-badge ${html(transaction.type)}">${html(tr(transaction.type))}</span>`;
}

function auditActionLabel(action) {
  return {
    created: tr("auditCreated"),
    updated: tr("auditUpdated"),
    deleted: tr("auditDeleted"),
    saved: tr("auditSaved"),
    queued: tr("auditQueued"),
    processed: tr("auditProcessed"),
    archived: tr("auditArchived"),
    restored: tr("auditRestored"),
    reset_password: tr("auditResetPassword"),
    disabled: tr("scheduleDisabled"),
  }[action] || action;
}

function auditEntityLabel(entity) {
  return {
    student: tr("auditStudent"),
    group: tr("auditGroup"),
    lesson: tr("auditLesson"),
    payment: tr("auditPayment"),
    message: tr("auditMessage"),
    attendance: tr("auditAttendance"),
    attendance_alerts: tr("auditAttendanceAlerts"),
    transaction: tr("auditTransaction"),
    telegram_settings: tr("auditTelegramSettings"),
    message_queue: tr("auditMessageQueue"),
    teacher: tr("auditTeacher"),
    teacher_working_hour: tr("auditTeacherWorkingHour"),
    group_schedule: tr("scheduleRules"),
  }[entity] || entity;
}

function studentDrawer() {
  if (!state.drawer) return "";
  const drawer = state.drawer;
  const student = drawer.student || studentById(drawer.studentId) || {};
  const status = student.status || "active";
  const tabs = state.role === "teacher"
    ? [["overview", "studentOverview"], ["groups", "groupHistory"], ["attendance", "attendance"]]
    : [["overview", "studentOverview"], ["groups", "groupHistory"], ["attendance", "attendance"], ["finance", "finance"], ["telegram", "telegram"]];
  return `<div class="drawer-backdrop" onclick="closeStudentDrawer()">
    <aside class="student-drawer student-profile-drawer" role="dialog" aria-modal="true" aria-label="${attr(student.name || tr("students"))}" onclick="event.stopPropagation()">
      <div class="drawer-header">
        <div>
          <h2>${html(student.name || tr("students"))}</h2>
          <div class="drawer-meta">${html([student.groupName, student.phone].filter(Boolean).join(" · "))}</div>
        </div>
        <button class="icon-button" aria-label="${attr(tr("cancel"))}" onclick="closeStudentDrawer()">${faIcon("fa-xmark")}</button>
        <div class="student-drawer-toolbar"><span class="status ${statusClass(status)}">${html(tr(status === "left" ? "archived" : status))}</span>${state.role === "admin" ? `<button class="ghost-button" type="button" onclick="editStudentFromDrawer()">${faIcon("fa-pen")} ${html(tr("edit"))}</button>${status === "left" ? `<button class="ghost-button" type="button" onclick="restoreStudent('${jsString(student.id)}')">${faIcon("fa-rotate-left")} ${html(tr("restoreStudent"))}</button>` : `<button class="ghost-button danger" type="button" onclick="archiveStudentFromDrawer()">${faIcon("fa-box-archive")} ${html(tr("archiveStudent"))}</button>`}` : `<span class="status info">${html(tr("readOnlyAccess"))}</span>`}</div>
      </div>
      <div class="drawer-tabs student-drawer-tabs" role="tablist">
        ${tabs.map(([tab, label]) => `<button class="drawer-tab ${drawer.tab === tab ? "active" : ""}" role="tab" aria-selected="${drawer.tab === tab ? "true" : "false"}" onclick="setDrawerTab('${tab}')">${html(tr(label))}</button>`).join("")}
      </div>
      <div class="drawer-body">${drawer.loading ? emptyInlineState("fa-spinner", tr("loading")) : drawerTabBody()}</div>
    </aside>
  </div>`;
}

function drawerTabBody() {
  if (!state.drawer) return "";
  if (state.drawer.tab === "groups") return studentGroupsTab();
  if (state.drawer.tab === "attendance") return studentAttendanceTab();
  if (state.drawer.tab === "finance") return studentFinanceTab();
  if (state.drawer.tab === "telegram") return studentTelegramTab();
  return studentOverviewTab();
}

function studentOverviewTab() {
  const drawer = state.drawer;
  const student = drawer.student || {};
  const guardian = (drawer.guardians || []).find((item) => item.isPrimary) || drawer.guardians?.[0] || {};
  const summary = drawer.attendance?.summary || {};
  if (state.role === "teacher") {
    return `<div class="drawer-stack"><div class="student-metric-grid"><div><span>${html(tr("currentGroup"))}</span><strong>${html(student.groupName || "—")}</strong></div><div><span>${html(tr("attendanceRate"))}</span><strong>${html(`${Number(summary.rate ?? student.attendanceRate ?? 0)}%`)}</strong></div><div><span>${html(tr("attendanceTotal"))}</span><strong>${html(summary.total ?? student.attendanceTotal ?? 0)}</strong></div><div><span>${html(tr("status"))}</span><strong>${html(tr(student.status || "active"))}</strong></div></div><section class="student-profile-section"><h3>${html(tr("contactDetails"))}</h3><div class="teacher-profile-fields"><div><span>${html(tr("studentPhone"))}</span><strong>${html(student.studentPhone || student.phone || "—")}</strong></div><div><span>Email</span><strong>${html(student.email || "—")}</strong></div><div><span>${html(tr("parent"))}</span><strong>${html(guardian.name || student.parentName || "—")}</strong></div><div><span>${html(tr("parentPhone"))}</span><strong>${html(guardian.phone || student.phone || "—")}</strong></div></div></section><section class="student-profile-section"><h3>${html(tr("learningDetails"))}</h3><div class="teacher-profile-fields"><div><span>${html(tr("birthDate"))}</span><strong>${html(student.birthDate || "—")}</strong></div><div><span>${html(tr("enrollmentDate"))}</span><strong>${html(student.enrollmentDate || "—")}</strong></div><div><span>${html(tr("level"))}</span><strong>${html(student.level || "—")}</strong></div><div><span>${html(tr("group"))}</span><strong>${html(student.groupName || "—")}</strong></div></div>${student.note ? `<div class="teacher-note"><span>${html(tr("note"))}</span><p>${html(student.note)}</p></div>` : ""}</section></div>`;
  }
  const balance = Number(drawer.balance ?? student.balance ?? 0);
  return `<div class="drawer-stack"><div class="student-metric-grid"><div><span>${html(tr("currentGroup"))}</span><strong>${html(student.groupName || "—")}</strong></div><div><span>${html(tr("attendanceRate"))}</span><strong>${html(`${Number(summary.rate ?? student.attendanceRate ?? 0)}%`)}</strong></div><div><span>${html(tr("balance"))}</span><strong class="${balance < 0 ? "negative" : "positive"}">${html(signedMoney(balance))}</strong></div><div><span>${html(tr("guardianTelegram"))}</span><strong>${html(tr((guardian.telegramChatId || student.telegramChatId) ? "connected" : "notConnected"))}</strong></div></div>
    <section class="student-profile-section"><h3>${html(tr("personalData"))}</h3><div class="teacher-profile-fields"><div><span>${html(tr("birthDate"))}</span><strong>${html(student.birthDate || "—")}</strong></div><div><span>${html(tr("gender"))}</span><strong>${html(student.gender ? tr(student.gender) : "—")}</strong></div><div><span>${html(tr("studentPhone"))}</span><strong>${html(student.studentPhone || "—")}</strong></div><div><span>Email</span><strong>${html(student.email || "—")}</strong></div><div><span>${html(tr("address"))}</span><strong>${html(student.address || "—")}</strong></div></div></section>
    <section class="student-profile-section"><h3>${html(tr("guardianData"))}</h3><div class="teacher-profile-fields"><div><span>${html(tr("fullName"))}</span><strong>${html(guardian.name || student.parentName || "—")}</strong></div><div><span>${html(tr("relationship"))}</span><strong>${html(tr(guardian.relationship || student.parentRelationship || "guardian"))}</strong></div><div><span>${html(tr("parentPhone"))}</span><strong>${html(guardian.phone || student.phone || "—")}</strong></div><div><span>${html(tr("parentEmail"))}</span><strong>${html(guardian.email || "—")}</strong></div></div></section>
    <section class="student-profile-section"><h3>${html(tr("academicData"))}</h3><div class="teacher-profile-fields"><div><span>${html(tr("enrollmentDate"))}</span><strong>${html(student.enrollmentDate || "—")}</strong></div><div><span>${html(tr("source"))}</span><strong>${html(student.source || "—")}</strong></div></div>${student.note ? `<div class="teacher-note"><span>${html(tr("note"))}</span><p>${html(student.note)}</p></div>` : ""}${student.archiveReason ? `<div class="teacher-note"><span>${html(tr("archiveReason"))}</span><p>${html(student.archiveReason)}</p></div>` : ""}</section></div>`;
}

function studentGroupsTab() {
  const rows = state.drawer.enrollments || [];
  if (!rows.length) return emptyInlineState("fa-layer-group", tr("noGroupHistory"));
  return `<div class="student-history-list">${rows.map((enrollment) => `<article><span class="student-history-icon">${faIcon(enrollment.status === "active" ? "fa-circle-check" : "fa-clock-rotate-left")}</span><div><strong>${html(enrollment.groupName || "—")}</strong><small>${html([enrollment.subject, enrollment.teacherName].filter(Boolean).join(" · "))}</small><small>${html(`${enrollment.startDate || "—"} — ${enrollment.endDate || tr("until")}`)}</small>${enrollment.reason ? `<p>${html(enrollment.reason)}</p>` : ""}</div><span class="status ${statusClass(enrollment.status)}">${html(tr(enrollment.status))}</span></article>`).join("")}</div>`;
}

function studentAttendanceTab() {
  const attendance = state.drawer.attendance || { summary: {}, records: [] };
  const summary = attendance.summary || {};
  const rows = attendance.records || [];
  return `<div class="drawer-stack"><div class="student-attendance-summary">${[["attendanceTotal", summary.total || 0], ["present", summary.present || 0], ["absent", summary.absent || 0], ["late", summary.late || 0], ["excused", summary.excused || 0]].map(([label, count]) => `<div><span>${html(tr(label))}</span><strong>${html(count)}</strong></div>`).join("")}</div>${rows.length ? `<div class="student-attendance-history">${rows.map((record) => `<article><div><strong>${html(record.lessonDate || record.createdAt?.slice(0, 10) || "—")}</strong><span>${html([record.groupName, record.subject, record.lessonTime].filter(Boolean).join(" · "))}</span></div><span class="status ${statusClass(record.status)}">${html(tr(record.status))}</span></article>`).join("")}</div>` : emptyInlineState("fa-clipboard-check", tr("noAttendanceRecords"))}</div>`;
}

function studentFinanceTab() {
  const payments = state.drawer.recentPayments || [];
  const subscriptions = state.drawer.subscriptions || [];
  return `<div class="drawer-stack">${balanceTab()}<section class="student-profile-section"><h3>${html(tr("history"))}</h3>${ledgerHistoryTab()}</section><section class="student-profile-section"><h3>${html(tr("recentPayments"))}</h3>${payments.length ? `<div class="student-payment-list">${payments.map((payment) => `<div><span>${html(payment.createdAt ? new Date(payment.createdAt).toLocaleDateString(currentLocale()) : "—")}</span><strong>${html(money(payment.amount))}</strong></div>`).join("")}</div>` : emptyInlineState("fa-credit-card", tr("noRecentPayments"))}</section><section class="student-profile-section"><div class="drawer-section-header"><h3>${html(tr("subscriptions"))}</h3>${state.role === "admin" ? `<button class="ghost-button" type="button" onclick="openSubscriptionModal('${jsString(state.drawer.studentId)}')">${faIcon("fa-plus")} ${html(tr("newSubscription"))}</button>` : ""}</div>${subscriptions.length ? `<div class="student-payment-list">${subscriptions.map((subscription) => `<div><span>${html(subscription.name || subscription.status || tr("subscriptions"))}</span><strong>${html([subscription.startDate, subscription.endDate].filter(Boolean).join(" — "))}</strong></div>`).join("")}</div>` : emptyInlineState("fa-ticket", tr("noSubscriptions"))}</section></div>`;
}

function balanceTab() {
  const drawer = state.drawer;
  const balance = Number(drawer.balance ?? drawer.student?.balance ?? 0);
  return `<div class="drawer-stack">
    <div class="balance-card">
      <div class="card-subtitle">${html(tr("walletBalance"))}</div>
      <div class="balance-value ${balance >= 0 ? "positive" : "negative"}">${html(money(balance))}</div>
      <div class="balance-caption">${html(balance < 0 ? tr("overallDebt") : tr("availableFunds"))}</div>
    </div>
    <div class="drawer-action-row">
      <button class="primary-button" onclick="toggleTransactionForm('payment')">${faIcon("fa-plus")} ${html(tr("addPayment"))}</button>
      <button class="ghost-button" onclick="toggleTransactionForm('charge')">${faIcon("fa-receipt")} ${html(tr("addCharge"))}</button>
    </div>
    ${drawer.form ? transactionForm(drawer.form) : ""}
  </div>`;
}

function transactionForm(type) {
  const isPayment = type === "payment";
  return `<form class="wallet-form" onsubmit="submitTransaction(event, '${jsString(type)}')">
    <div class="field"><label>${html(tr("amount"))}</label><input id="walletAmount" type="number" min="1" step="1" placeholder="0" required /></div>
    <div class="field"><label>${html(tr("description"))}</label><input id="walletDescription" placeholder="${attr(isPayment ? tr("paymentNotePlaceholder") : tr("chargeNotePlaceholder"))}" /></div>
    ${isPayment ? `<div class="field"><label>${html(tr("paymentMethod"))}</label><select id="walletMethod"><option value="cash">${html(tr("cash"))}</option><option value="click">${html(tr("click"))}</option><option value="payme">${html(tr("payme"))}</option><option value="bank">${html(tr("bank"))}</option></select></div>` : ""}
    <div class="wallet-form-actions">
      <button class="primary-button" type="submit" ${state.drawer.saving ? "disabled" : ""}>${html(state.drawer.saving ? tr("saving") : tr("save"))}</button>
      <button class="ghost-button" type="button" onclick="toggleTransactionForm(null)" ${state.drawer.saving ? "disabled" : ""}>${html(tr("cancel"))}</button>
    </div>
  </form>`;
}

function ledgerHistoryTab() {
  const rows = state.drawer.ledger || [];
  if (!rows.length) return emptyInlineState("fa-receipt", tr("noTransactions"));
  return `<div class="table-wrap ledger-table desktop-table-wrap"><table><thead><tr><th>${html(tr("date"))}</th><th>${html(tr("type"))}</th><th>${html(tr("description"))}</th><th>${html(tr("amount"))}</th></tr></thead><tbody>
    ${rows.map((transaction) => {
      const signed = ledgerAmount(transaction);
      return `<tr><td>${html(transaction.invoiceDate || "")}</td><td>${transactionBadge(transaction)}</td><td>${html(transaction.description || "")}</td><td class="ledger-amount ${signed >= 0 ? "positive" : "negative"}">${html(signedMoney(signed))}</td></tr>`;
    }).join("")}
  </tbody></table></div><div class="mobile-record-list">${rows.map((transaction) => {
    const signed = ledgerAmount(transaction);
    return `<article class="mobile-record-card">
      <div class="mobile-record-main">
        <div class="mobile-record-title">${html(transaction.invoiceDate || "")}</div>
        <div class="ledger-amount ${signed >= 0 ? "positive" : "negative"}">${html(signedMoney(signed))}</div>
      </div>
      <div class="mobile-record-details">
        <div class="mobile-record-field"><span>${html(tr("type"))}</span><strong>${transactionBadge(transaction)}</strong></div>
        <div class="mobile-record-field"><span>${html(tr("description"))}</span><strong>${html(transaction.description || "")}</strong></div>
      </div>
    </article>`;
  }).join("")}</div>`;
}

function studentInfoTab() {
  const student = state.drawer.student || studentById(state.drawer.studentId) || {};
  return `<div class="form-grid">
    <div class="field"><label>${html(tr("fullName"))}</label><input value="${attr(student.name || "")}" readonly /></div>
    <div class="field"><label>${html(tr("phone"))}</label><input value="${attr(student.phone || "")}" readonly /></div>
    <div class="field"><label>${html(tr("parent"))}</label><input value="${attr(student.parentName || "")}" readonly /></div>
    <div class="field"><label>${html(tr("group"))}</label><input value="${attr(student.groupName || "")}" readonly /></div>
    <div class="field"><label>${html(tr("status"))}</label><input value="${attr(tr(student.status || "active"))}" readonly /></div>
    <div class="field"><label>${html(tr("balance"))}</label><input value="${attr(money(state.drawer.balance || 0))}" readonly /></div>
  </div>`;
}

function studentTelegramTab() {
  const student = state.drawer.student || studentById(state.drawer.studentId) || {};
  const guardian = (state.drawer.guardians || []).find((item) => item.isPrimary) || state.drawer.guardians?.[0] || {};
  const telegramChatId = guardian.telegramChatId || student.telegramChatId || "";
  const connected = Boolean(telegramChatId);
  const pairingUrl = state.drawer.telegramLink?.url || "";
  return `<div class="telegram-connect-panel">
    <div class="telegram-connect-header">
      <span class="telegram-connect-icon">${faIcon("fa-telegram", "fa-brands")}</span>
      <div><h3>${html(tr("telegramSetupTitle"))}</h3><p>${html(tr("telegramSetupDescription"))}</p></div>
      <span class="telegram-connection-badge ${connected ? "connected" : ""}">${html(tr(connected ? "connected" : "notConnected"))}</span>
    </div>
    ${connected ? "" : `<ol class="telegram-connect-steps"><li>${html(tr("telegramStepCreate"))}</li><li>${html(tr("telegramStepShare"))}</li><li>${html(tr("telegramStepStart"))}</li></ol>`}
    <button class="primary-button telegram-connect-cta" type="button" onclick="createStudentTelegramLink()" ${state.drawer.saving ? "disabled" : ""}>${faIcon("fa-link")} ${html(state.drawer.saving ? tr("saving") : tr(connected ? "reconnectTelegram" : "createTelegramLink"))}</button>
    ${pairingUrl ? `<div class="telegram-pairing-link"><span>${faIcon("fa-clock")} ${html(tr("telegramLinkReady"))}</span><a href="${attr(pairingUrl)}" target="_blank" rel="noopener">${html(pairingUrl)}</a><div class="telegram-pairing-actions"><button class="ghost-button" type="button" onclick="copyTelegramLink('${jsString(pairingUrl)}')">${faIcon("fa-copy")} ${html(tr("copyLink"))}</button><a class="primary-button" href="${attr(pairingUrl)}" target="_blank" rel="noopener">${faIcon("fa-arrow-up-right-from-square")} ${html(tr("openInTelegram"))}</a></div></div>` : ""}
    <details class="telegram-manual-connect">
      <summary>${html(tr("manualConnection"))}</summary>
      <form onsubmit="saveStudentChatId(event)"><p>${html(tr("manualConnectionHint"))}</p><div class="field"><label>${html(tr("telegramChatId"))}</label><input id="studentTelegramChatId" type="text" inputmode="numeric" placeholder="123456789" value="${attr(telegramChatId)}" /></div><button class="ghost-button" type="submit" ${state.drawer.saving ? "disabled" : ""}>${html(state.drawer.saving ? tr("saving") : tr("save"))}</button></form>
    </details>
  </div>`;
}

function groupDrawer() {
  const drawer = state.groupDrawer;
  if (!drawer) return "";
  const group = drawer.group || groupById(drawer.groupId) || {};
  const status = groupStatus(group);
  const tabs = [["overview", "groupOverview"], ["members", "groupMembers"], ["schedule", "groupSchedule"], ["lessons", "lessonsAndAttendance"]];
  if (state.role === "admin") tabs.push(["finance", "groupFinance"]);
  const adminToolbar = state.role === "admin"
    ? `<button class="ghost-button" type="button" onclick="editGroupFromDrawer()">${faIcon("fa-pen")} ${html(tr("edit"))}</button>${status === "archived" ? `<button class="ghost-button" type="button" onclick="restoreGroup('${jsString(group.id)}')">${faIcon("fa-rotate-left")} ${html(tr("restoreGroup"))}</button>` : `<button class="ghost-button danger" type="button" onclick="archiveGroupFromDrawer()">${faIcon("fa-box-archive")} ${html(tr("archiveGroup"))}</button>`}`
    : "";
  return `<div class="drawer-backdrop" onclick="closeGroupDrawer()"><aside class="student-drawer group-profile-drawer" role="dialog" aria-modal="true" aria-label="${attr(group.name || tr("groupProfile"))}" onclick="event.stopPropagation()"><div class="drawer-header"><div><h2>${html(group.name || tr("groupProfile"))}</h2><div class="drawer-meta">${html([group.subject, group.level, group.teacherName].filter(Boolean).join(" · "))}</div></div><button class="icon-button" type="button" onclick="closeGroupDrawer()" aria-label="${attr(tr("cancel"))}">${faIcon("fa-xmark")}</button><div class="student-drawer-toolbar"><span class="status ${statusClass(status)}">${html(tr(status))}</span>${adminToolbar}</div></div><div class="drawer-tabs group-drawer-tabs" role="tablist">${tabs.map(([tab,label]) => `<button class="drawer-tab ${drawer.tab === tab ? "active" : ""}" type="button" onclick="setGroupDrawerTab('${tab}')">${html(tr(label))}</button>`).join("")}</div><div class="drawer-body">${drawer.loading ? emptyInlineState("fa-spinner", tr("loading")) : groupDrawerBody()}</div></aside></div>`;
}

function groupDrawerBody() {
  if (!state.groupDrawer) return "";
  if (state.groupDrawer.tab === "members") return groupMembersTab();
  if (state.groupDrawer.tab === "schedule") return groupScheduleTab();
  if (state.groupDrawer.tab === "lessons") return groupLessonsTab();
  if (state.groupDrawer.tab === "finance") return groupFinanceTab();
  return groupOverviewTab();
}

function groupOverviewTab() {
  const drawer = state.groupDrawer;
  const group = drawer.group || {};
  const attendance = drawer.attendance?.summary || {};
  const finance = drawer.finance || {};
  const capacity = Number(group.capacity || 0);
  const count = Number(group.studentsCount || drawer.members?.active?.length || 0);
  const available = capacity > 0 ? Math.max(capacity - count, 0) : tr("unlimited");
  const assignments = drawer.teacherAssignments || [];
  const fourthMetric = state.role === "admin"
    ? `<div><span>${html(tr("monthlyPotential"))}</span><strong>${html(money(finance.monthlyPotential ?? count * Number(group.monthlyFee || 0)))}</strong></div>`
    : `<div><span>${html(tr("schedule"))}</span><strong>${html(group.scheduleSummary || "—")}</strong></div>`;
  const privateField = state.role === "admin" ? `<div><span>${html(tr("monthlyFee"))}</span><strong>${html(money(group.monthlyFee || 0))}</strong></div>` : "";
  return `<div class="drawer-stack"><div class="student-metric-grid group-metric-grid"><div><span>${html(tr("occupancy"))}</span><strong>${html(capacity > 0 ? `${count} / ${capacity}` : `${count} / ∞`)}</strong></div><div><span>${html(tr("availableSeats"))}</span><strong>${html(available)}</strong></div><div><span>${html(tr("attendanceAverage"))}</span><strong>${html(`${Number(attendance.rate || group.attendanceRate || 0)}%`)}</strong></div>${fourthMetric}</div><section class="student-profile-section"><h3>${html(tr("groupOverview"))}</h3><div class="teacher-profile-fields"><div><span>${html(tr("subject"))}</span><strong>${html(group.subject || "—")}</strong></div><div><span>${html(tr("level"))}</span><strong>${html(group.level || "—")}</strong></div><div><span>${html(tr("mainTeacher"))}</span><strong>${html(group.teacherName || "—")}</strong></div><div><span>${html(tr("room"))}</span><strong>${html(group.room || "—")}</strong></div><div><span>${html(tr("period"))}</span><strong>${html([group.startDate, group.endDate].filter(Boolean).join(" — ") || "—")}</strong></div>${privateField}</div>${group.description ? `<div class="teacher-note"><span>${html(tr("groupDescription"))}</span><p>${html(group.description)}</p></div>` : ""}${group.note ? `<div class="teacher-note"><span>${html(tr("note"))}</span><p>${html(group.note)}</p></div>` : ""}${group.archiveReason ? `<div class="teacher-note"><span>${html(tr("archiveReason"))}</span><p>${html(group.archiveReason)}</p></div>` : ""}</section><section class="student-profile-section"><h3>${html(tr("teacherHistory"))}</h3>${assignments.length ? `<div class="student-history-list">${assignments.map((assignment) => `<article><span class="student-history-icon">${faIcon("fa-chalkboard-user")}</span><div><strong>${html(assignment.teacherName || "—")}</strong><small>${html(`${assignment.startDate || "—"} — ${assignment.endDate || tr("active")}`)}</small></div><span class="status ${statusClass(assignment.status)}">${html(tr(assignment.status))}</span></article>`).join("")}</div>` : emptyInlineState("fa-chalkboard-user", tr("noData"))}</section></div>`;
}

function groupMembersTab() {
  const members = state.groupDrawer.members || { active: [], history: [] };
  const group = state.groupDrawer.group || {};
  return `<div class="drawer-stack"><section class="student-profile-section"><div class="drawer-section-header"><h3>${html(tr("activeMembers"))}</h3><div class="row-actions"><span class="status success">${html(members.active?.length || 0)}</span>${state.role === "admin" && groupStatus(group) === "active" ? `<button class="primary-button" type="button" onclick="addStudentFromGroupDrawer()">${faIcon("fa-user-plus")} ${html(tr("newStudent"))}</button>` : ""}</div></div>${members.active?.length ? `<div class="group-member-list">${members.active.map((student) => `<article><div>${studentNameButton(student)}<small>${html([student.parentName, student.phone].filter(Boolean).join(" · "))}</small></div><span class="status ${statusClass(student.status || "active")}">${html(tr(student.status || "active"))}</span></article>`).join("")}</div>` : emptyInlineState("fa-users", tr("noActiveMembers"))}</section><section class="student-profile-section"><h3>${html(tr("formerMembers"))}</h3>${members.history?.length ? `<div class="student-history-list">${members.history.map((membership) => `<article><span class="student-history-icon">${faIcon("fa-clock-rotate-left")}</span><div><strong>${html(membership.studentName || membership.name || "—")}</strong><small>${html(`${membership.startDate || "—"} — ${membership.endDate || tr("active")}`)}</small>${membership.reason ? `<p>${html(membership.reason)}</p>` : ""}</div><span class="status ${statusClass(membership.status)}">${html(tr(membership.status))}</span></article>`).join("")}</div>` : emptyInlineState("fa-clock-rotate-left", tr("noMembershipHistory"))}</section></div>`;
}

function weekdayLabel(value) {
  const days = i18n[state.lang]?.weekDaysFull || i18n.uz.weekDaysFull;
  return days[Number(value) % 7] || "";
}

function nextGroupScheduleOccurrence(schedule) {
  const validFrom = schedule?.validFrom || todayIso();
  const startValue = validFrom > todayIso() ? validFrom : todayIso();
  const start = dateFromIso(startValue);
  const targetWeekday = Number(schedule?.weekday || 1);
  if (!start || !Number.isInteger(targetWeekday) || targetWeekday < 1 || targetWeekday > 7) return "";
  const currentWeekday = start.getUTCDay() || 7;
  const candidate = isoDate(addDays(start, (targetWeekday - currentWeekday + 7) % 7));
  if (!schedule?.validUntil || candidate <= schedule.validUntil) return candidate;
  const end = dateFromIso(schedule.validUntil);
  if (!end) return "";
  const endWeekday = end.getUTCDay() || 7;
  const fallback = isoDate(addDays(end, -((endWeekday - targetWeekday + 7) % 7)));
  return fallback >= validFrom ? fallback : "";
}

function scheduleSnapshotRows(snapshot) {
  if (!snapshot) return `<p class="schedule-preview-stopped">${html(tr("scheduleStoppedAfter"))}</p>`;
  const date = snapshot.date || "—";
  const time = [snapshot.startTime, snapshot.endTime].filter(Boolean).join(" — ") || "—";
  const teacher = snapshot.teacherName || snapshot.teacherId || "—";
  const room = snapshot.roomName || snapshot.roomId || tr("notSpecified");
  return `<dl><div><dt>${html(tr("date"))}</dt><dd>${html(date)}</dd></div><div><dt>${html(tr("weekday"))}</dt><dd>${html(weekdayLabel(snapshot.weekday))}</dd></div><div><dt>${html(tr("time"))}</dt><dd>${html(time)}</dd></div><div><dt>${html(tr("teacher"))}</dt><dd>${html(teacher)}</dd></div><div><dt>${html(tr("room"))}</dt><dd>${html(room)}</dd></div></dl>`;
}

function groupScheduleChangePreview() {
  const preview = state.groupDrawer?.scheduleForm?.preview;
  if (!preview) return "";
  const impact = preview.impact || {};
  const impactRows = [
    impact.createsOccurrenceException ? tr("scheduleOccurrenceException") : "",
    impact.closesSeriesVersion ? tr("scheduleSeriesClosed") : "",
    impact.createsSeriesVersion ? tr("scheduleSeriesVersionCreated") : "",
    impact.nextSeriesVersion ? `${tr("scheduleNextVersion")}: ${impact.nextSeriesVersion}` : "",
    impact.firstOccurrenceDate ? `${tr("scheduleFirstOccurrence")}: ${impact.firstOccurrenceDate}` : "",
    Number(impact.materializedLessonsPreserved || 0) > 0
      ? `${tr("scheduleMaterializedPreserved")}: ${Number(impact.materializedLessonsPreserved)}`
      : "",
  ].filter(Boolean);
  const warnings = (Array.isArray(preview.warnings) ? preview.warnings : []).map((warning) => (
    warning === "Existing materialized lessons are preserved as historical snapshots"
      ? tr("scheduleMaterializedWarning")
      : warning
  ));
  return `<section class="group-schedule-preview span-2" aria-live="polite"><div class="group-schedule-preview-header"><div><span>${faIcon("fa-shield-check")}</span><strong>${html(tr("scheduleChangePreview"))}</strong></div><span class="status info">${html(tr(preview.scope || "this_and_future"))}</span></div><div class="group-schedule-preview-compare"><article><h4>${html(tr("scheduleBefore"))}</h4>${scheduleSnapshotRows(preview.before)}</article><article><h4>${html(tr("scheduleAfter"))}</h4>${scheduleSnapshotRows(preview.after)}</article></div>${impactRows.length ? `<div class="group-schedule-impact"><strong>${html(tr("scheduleImpact"))}</strong><ul>${impactRows.map((row) => `<li>${html(row)}</li>`).join("")}</ul></div>` : ""}${warnings.length ? `<div class="group-schedule-warnings">${warnings.map((warning) => `<p>${faIcon("fa-triangle-exclamation")} ${html(warning)}</p>`).join("")}</div>` : ""}<div class="wallet-form-actions"><button class="primary-button" type="button" onclick="confirmGroupScheduleChange()" ${state.groupDrawer?.saving ? "disabled" : ""}>${faIcon("fa-check")} ${html(tr("confirmScheduleChange"))}</button></div></section>`;
}

function groupScheduleForm() {
  const form = state.groupDrawer.scheduleForm;
  if (!form) return "";
  if (state.role !== "admin") return "";
  const group = state.groupDrawer.group || {};
  const teachers = (state.data.teachers || []).filter((teacher) => teacher.status === "active" || teacher.id === form.teacherId);
  const rooms = state.groupDrawer.rooms || [];
  const editing = Boolean(form.id);
  const changeFields = editing
    ? `<div class="field"><label>${html(tr("scheduleOccurrenceDate"))}</label><input id="groupScheduleOccurrenceDate" type="date" value="${attr(form.occurrenceDate || nextGroupScheduleOccurrence(form))}" required /></div><div class="field"><label>${html(tr("scheduleChangeScope"))}</label><select id="groupScheduleScope" required ${form.disableIntent ? "disabled" : ""} onchange="setGroupScheduleChangeScope(this.value)"><option value="this_occurrence" ${form.scope !== "this_and_future" ? "selected" : ""}>${html(tr("this_occurrence"))}</option><option value="this_and_future" ${form.scope === "this_and_future" ? "selected" : ""}>${html(tr("this_and_future"))}</option></select></div><div class="field span-2"><label>${html(tr("scheduleChangeReason"))}</label><textarea id="groupScheduleReason" maxlength="500" placeholder="${attr(tr("scheduleChangeReasonPlaceholder"))}" required>${html(form.reason || "")}</textarea></div>${form.disableIntent ? `<p class="group-schedule-disable-hint span-2">${faIcon("fa-circle-info")} ${html(tr("scheduleDisableHint"))}</p>` : ""}`
    : `<div class="field"><label>${html(tr("validFrom"))}</label><input id="groupScheduleFrom" type="date" value="${attr(form.validFrom || group.startDate || todayIso())}" required /></div><div class="field"><label>${html(tr("status"))}</label><select id="groupScheduleStatus"><option value="active" ${form.status !== "inactive" ? "selected" : ""}>${html(tr("active"))}</option><option value="inactive" ${form.status === "inactive" ? "selected" : ""}>${html(tr("inactive"))}</option></select></div>`;
  const seriesFields = !editing || form.scope === "this_and_future"
    ? `<div class="field"><label>${html(tr("validUntil"))}</label><input id="groupScheduleUntil" type="date" value="${attr(form.validUntil || group.endDate || "")}" /></div><div class="field"><label>${html(tr("onlineLink"))}</label><input id="groupScheduleLink" type="url" value="${attr(form.lessonLink || "")}" placeholder="https://meet.google.com/..." /></div>`
    : "";
  return `<form class="group-schedule-form" onsubmit="saveGroupSchedule(event)"><div class="field"><label>${html(tr("weekday"))}</label><select id="groupScheduleWeekday" required>${[1,2,3,4,5,6,7].map((day) => `<option value="${day}" ${Number(form.weekday || 1) === day ? "selected" : ""}>${html(weekdayLabel(day))}</option>`).join("")}</select></div><div class="field"><label>${html(tr("startTime"))}</label><input id="groupScheduleStart" type="time" value="${attr(form.startTime || "09:00")}" required /></div><div class="field"><label>${html(tr("endTime"))}</label><input id="groupScheduleEnd" type="time" value="${attr(form.endTime || "10:00")}" required /></div><div class="field"><label>${html(tr("teacher"))}</label><select id="groupScheduleTeacher" required>${teachers.map((teacher) => `<option value="${attr(teacher.id)}" ${(form.teacherId || group.teacherId) === teacher.id ? "selected" : ""}>${html(teacher.name)}</option>`).join("")}</select></div><div class="field"><label>${html(tr("room"))}</label><select id="groupScheduleRoom"><option value="">${html(group.room || tr("notSpecified"))}</option>${rooms.map((room) => `<option value="${attr(room.id)}" ${form.roomId === room.id ? "selected" : ""}>${html(room.name)}</option>`).join("")}</select></div>${changeFields}${seriesFields}${groupScheduleChangePreview()}<div class="wallet-form-actions span-2"><button class="primary-button" type="submit" ${state.groupDrawer.saving ? "disabled" : ""}>${html(state.groupDrawer.saving ? tr("saving") : editing ? tr("previewScheduleChange") : tr("save"))}</button><button class="ghost-button" type="button" onclick="toggleGroupScheduleForm()" ${state.groupDrawer.saving ? "disabled" : ""}>${html(tr("cancel"))}</button></div></form>`;
}

function groupScheduleTab() {
  const drawer = state.groupDrawer;
  const group = drawer.group || {};
  const schedules = drawer.schedules || [];
  const canManage = state.role === "admin";
  return `<div class="drawer-stack"><div class="drawer-section-header"><div><h3>${html(tr("scheduleRules"))}</h3><div class="card-subtitle">${html(group.name || "")}</div></div>${canManage && ["active", "draft"].includes(groupStatus(group)) ? `<button class="primary-button" type="button" onclick="toggleGroupScheduleForm()">${faIcon("fa-plus")} ${html(tr("addSchedule"))}</button>` : ""}</div>${groupScheduleForm()}${schedules.length ? `<div class="group-schedule-list">${schedules.map((schedule) => `<article class="${schedule.status === "inactive" ? "inactive" : ""}"><div class="group-schedule-day"><strong>${html(weekdayLabel(schedule.weekday))}</strong><span>${html(`${schedule.startTime} — ${schedule.endTime}`)}</span></div><div><strong>${html(schedule.teacherName || group.teacherName || "—")}</strong><small>${html([schedule.roomName || group.room, [schedule.validFrom, schedule.validUntil].filter(Boolean).join(" — ")].filter(Boolean).join(" · "))}</small></div><span class="status ${statusClass(schedule.status)}">${html(tr(schedule.status))}</span>${canManage && schedule.status !== "inactive" ? `<div class="row-actions"><button class="icon-button table-icon-action" type="button" onclick="toggleGroupScheduleForm('${jsString(schedule.id)}')" title="${attr(tr("edit"))}">${faIcon("fa-pen")}</button><button class="icon-button table-icon-action danger" type="button" onclick="disableGroupSchedule('${jsString(schedule.id)}')" title="${attr(tr("disableSchedule"))}">${faIcon("fa-ban")}</button></div>` : ""}</article>`).join("")}</div>` : emptyInlineState("fa-calendar-days", tr("noSchedules"))}</div>`;
}

function groupLessonsTab() {
  const lessons = state.groupDrawer.lessons || { summary: {}, upcoming: [], recent: [] };
  const attendance = state.groupDrawer.attendance || { summary: {}, records: [] };
  const summary = lessons.summary || {};
  const rows = [...(lessons.upcoming || []), ...(lessons.recent || [])].filter((lesson, index, all) => all.findIndex((item) => item.id === lesson.id) === index).slice(0, 20);
  return `<div class="drawer-stack"><div class="student-attendance-summary group-lesson-summary"><div><span>${html(tr("plannedLessons"))}</span><strong>${html(summary.planned || 0)}</strong></div><div><span>${html(tr("completedGroupLessons"))}</span><strong>${html(summary.completed || 0)}</strong></div><div><span>${html(tr("cancelledLessons"))}</span><strong>${html(summary.cancelled || 0)}</strong></div><div><span>${html(tr("attendanceAverage"))}</span><strong>${html(`${Number(attendance.summary?.rate || 0)}%`)}</strong></div></div>${rows.length ? `<div class="student-attendance-history">${rows.map((lesson) => `<article><div><strong>${html(`${lesson.date || "—"} · ${lesson.time || ""}`)}</strong><span>${html([lesson.teacherName, lesson.room].filter(Boolean).join(" · "))}</span></div><span class="status ${statusClass(lesson.status)}">${html(tr(lesson.status))}</span></article>`).join("")}</div>` : emptyInlineState("fa-book-open", tr("noGroupLessons"))}</div>`;
}

function groupFinanceTab() {
  const finance = state.groupDrawer.finance || {};
  const debtors = finance.debtors || [];
  const policies = state.groupDrawer.billingPolicies || [];
  const group = state.groupDrawer.group || {};
  return `<div class="drawer-stack"><div class="student-metric-grid group-finance-grid"><div><span>${html(tr("monthlyPotential"))}</span><strong>${html(money(finance.monthlyPotential || 0))}</strong></div><div><span>${html(tr("chargedTotal"))}</span><strong>${html(money(finance.charged || 0))}</strong></div><div><span>${html(tr("paidTotal"))}</span><strong class="positive">${html(money(finance.paid || 0))}</strong></div><div><span>${html(tr("outstandingTotal"))}</span><strong class="negative">${html(money(finance.outstanding || 0))}</strong></div></div>${state.role === "admin" ? `<section class="student-profile-section"><h3>${html(tr("lessonBillingPolicy"))}</h3>${policies.length ? `<div class="student-history-list">${policies.map((policy) => `<article><span class="student-history-icon">${faIcon("fa-receipt")}</span><div><strong>${html(`${policy.name} · ${money(policy.baseAmount)}`)}</strong><small>${html(`${policy.validFrom} — ${policy.validUntil || tr("active")}`)}</small></div><span class="status ${statusClass(policy.status)}">${html(tr(policy.status))}</span></article>`).join("")}</div>` : emptyInlineState("fa-receipt", tr("financeNotReady"))}<form class="finance-policy-form" onsubmit="addGroupBillingPolicy(event)"><div class="field"><label>${html(tr("description"))}</label><input id="groupBillingName" value="${attr(`${group.name || ""} tarifi`)}" maxlength="120" required /></div><div class="field"><label>${html(tr("baseLessonPrice"))}</label><input id="groupBillingAmount" type="number" min="0" step="1" required /></div><div class="field"><label>${html(tr("validFrom"))}</label><input id="groupBillingFrom" type="date" value="${attr(todayIso())}" required /></div><div class="field"><label>${html(tr("validUntil"))}</label><input id="groupBillingUntil" type="date" /></div><button class="primary-button" type="submit" ${state.groupDrawer.saving ? "disabled" : ""}>${faIcon("fa-plus")} ${html(tr("addBillingPolicy"))}</button></form></section>` : ""}<section class="student-profile-section"><h3>${html(tr("debtors"))}</h3>${debtors.length ? `<div class="group-member-list">${debtors.map((student) => `<article><div>${studentNameButton(student)}<small>${html(student.phone || "")}</small></div><strong class="student-balance negative">${html(money(student.debt || 0))}</strong></article>`).join("")}</div>` : emptyInlineState("fa-circle-check", tr("noDebtors"))}</section></div>`;
}

async function addGroupBillingPolicy(event) {
  event.preventDefault();
  if (!state.groupDrawer || state.groupDrawer.saving) return;
  state.groupDrawer.saving = true;
  render();
  try {
    await api("/api/finance/lesson-billing-policies", {
      method: "POST",
      body: JSON.stringify({
        groupId: state.groupDrawer.groupId,
        name: val("groupBillingName"),
        baseAmount: Number(val("groupBillingAmount")),
        validFrom: val("groupBillingFrom"),
        validUntil: val("groupBillingUntil"),
      }),
    });
    await refreshGroupDrawer();
    showToast(tr("saved"));
    render();
  } catch (error) {
    if (state.groupDrawer) state.groupDrawer.saving = false;
    showToast(errorMessage(error));
    render();
  }
}

function teacherDrawer() {
  const drawer = state.teacherDrawer;
  if (!drawer) return "";
  const teacher = drawer.teacher || teacherById(drawer.teacherId) || {};
  const tabs = [["overview", "teacherOverview"], ["groups", "teacherGroups"], ["schedule", "workingHours"]];
  if (state.role === "admin") tabs.push(["access", "portalAccess"]);
  return `<div class="drawer-backdrop" onclick="closeTeacherDrawer()"><aside class="student-drawer teacher-drawer" role="dialog" aria-modal="true" aria-label="${attr(teacher.name || tr("teacher"))}" onclick="event.stopPropagation()"><div class="drawer-header"><div><h2>${html(teacher.name || tr("teacher"))}</h2><div class="drawer-meta">${html(teacher.specialization || tr(teacher.employmentType || "full_time"))}</div></div><button class="icon-button" type="button" onclick="closeTeacherDrawer()" aria-label="${attr(tr("cancel"))}">${faIcon("fa-xmark")}</button><span class="status ${statusClass(teacher.status)}">${html(tr(teacher.status || "active"))}</span>${state.role === "admin" ? `<button class="ghost-button teacher-drawer-edit" type="button" onclick="editTeacherFromDrawer()">${faIcon("fa-pen")} ${html(tr("edit"))}</button>` : ""}</div><div class="drawer-tabs teacher-drawer-tabs" role="tablist">${tabs.map(([tab, label]) => `<button class="drawer-tab ${drawer.tab === tab ? "active" : ""}" type="button" onclick="setTeacherDrawerTab('${tab}')">${html(tr(label))}</button>`).join("")}</div><div class="drawer-body">${drawer.loading ? emptyInlineState("fa-spinner", tr("loading")) : teacherDrawerBody()}</div></aside></div>`;
}

function teacherDrawerBody() {
  if (!state.teacherDrawer) return "";
  if (state.teacherDrawer.tab === "groups") return teacherGroupsTab();
  if (state.teacherDrawer.tab === "schedule") return teacherScheduleTab();
  if (state.teacherDrawer.tab === "access") return teacherAccessTab();
  return teacherOverviewTab();
}

function teacherOverviewTab() {
  const teacher = state.teacherDrawer.teacher || {};
  return `<div class="drawer-stack"><div class="teacher-metric-grid"><div><span>${html(tr("groups"))}</span><strong>${html(teacher.groupsCount || 0)}</strong></div><div><span>${html(tr("students"))}</span><strong>${html(teacher.studentsCount || 0)}</strong></div><div><span>${html(tr("weeklyLoad"))}</span><strong>${html((Number(teacher.weeklyMinutes || 0) / 60).toLocaleString(currentLocale(), { maximumFractionDigits: 1 }))} ${html(tr("hoursShort"))}</strong></div><div><span>${html(tr("completedLessons"))}</span><strong>${html(teacher.completedLessons || 0)}</strong></div></div><div class="teacher-profile-fields"><div><span>${html(tr("phone"))}</span><strong>${html(teacher.phone || "—")}</strong></div><div><span>Email</span><strong>${html(teacher.email || "—")}</strong></div><div><span>${html(tr("employmentType"))}</span><strong>${html(tr(teacher.employmentType || "full_time"))}</strong></div><div><span>${html(tr("hiredAt"))}</span><strong>${html(teacher.hiredAt || "—")}</strong></div><div><span>${html(tr("maxWeeklyHours"))}</span><strong>${html((Number(teacher.maxWeeklyMinutes || 0) / 60).toLocaleString(currentLocale()))}</strong></div></div>${teacher.note ? `<div class="teacher-note"><span>${html(tr("note"))}</span><p>${html(teacher.note)}</p></div>` : ""}</div>`;
}

function teacherGroupsTab() {
  const groups = state.teacherDrawer.groups || [];
  if (!groups.length) return emptyInlineState("fa-layer-group", tr("noTeacherGroups"));
  return `<div class="teacher-group-list">${groups.map((group) => `<article><div><strong>${html(group.name)}</strong><span>${html(group.subject)} · ${html(group.room || "—")}</span></div><span class="status ${group.active ? "success" : "info"}">${html(group.studentsCount || 0)} ${html(tr("students"))}</span></article>`).join("")}</div>`;
}

function teacherScheduleTab() {
  const drawer = state.teacherDrawer;
  const hours = drawer.workingHours || [];
  const lessons = drawer.upcomingLessons || [];
  const rateRules = drawer.rateRules || [];
  const groups = drawer.groups || [];
  const weekdays = i18n[state.lang]?.weekDaysShort || i18n.uz.weekDaysShort;
  const hoursForm = state.role === "admin" ? `<form class="teacher-hours-form" onsubmit="addTeacherWorkingHour(event)"><div class="field"><label>${html(tr("weekday"))}</label><select id="teacherWeekday">${weekdays.map((day, index) => `<option value="${index + 1}">${html(day)}</option>`).join("")}</select></div><div class="field"><label>${html(tr("startTime"))}</label><input id="teacherStartTime" type="time" value="09:00" required /></div><div class="field"><label>${html(tr("endTime"))}</label><input id="teacherEndTime" type="time" value="18:00" required /></div><button class="primary-button" type="submit" ${drawer.saving ? "disabled" : ""}>${faIcon("fa-plus")} ${html(tr("addWorkingHour"))}</button></form>` : "";
  return `<div class="drawer-stack"><section class="teacher-drawer-section"><div class="drawer-section-header"><h3>${html(tr("workingHours"))}</h3></div>${hoursForm}<div class="working-hours-list">${hours.map((hour) => `<div><span><strong>${html(weekdays[Number(hour.weekday) - 1] || hour.weekday)}</strong>${html(hour.startTime)}–${html(hour.endTime)}</span>${state.role === "admin" ? `<button class="icon-button table-icon-action danger" type="button" onclick="deleteTeacherWorkingHour('${jsString(hour.id)}')" ${drawer.saving ? "disabled" : ""}>${faIcon("fa-trash-can")}</button>` : ""}</div>`).join("") || `<p class="card-subtitle">${html(tr("noWorkingHours"))}</p>`}</div></section>${state.role === "admin" ? `<section class="teacher-drawer-section"><div class="drawer-section-header"><h3>${html(tr("teacherRate"))}</h3></div>${rateRules.length ? `<div class="working-hours-list">${rateRules.map((rule) => `<div><span><strong>${html(`${tr(rule.rateType)} · ${money(rule.amount)}`)}</strong>${html(`${rule.groupName || tr("all")} · ${rule.effectiveFrom} — ${rule.effectiveUntil || tr("active")}`)}</span>${rule.status === "active" ? `<button class="icon-button table-icon-action danger" type="button" onclick="archiveTeacherRateRule('${jsString(rule.id)}')" ${drawer.saving ? "disabled" : ""}>${faIcon("fa-box-archive")}</button>` : ""}</div>`).join("")}</div>` : `<p class="card-subtitle">${html(tr("noTeacherRate"))}</p>`}<form class="teacher-rate-form" onsubmit="addTeacherRateRule(event)"><div class="field"><label>${html(tr("rateType"))}</label><select id="teacherRateType"><option value="flat">${html(tr("flat"))}</option><option value="per_student">${html(tr("per_student"))}</option><option value="hourly">${html(tr("hourly"))}</option></select></div><div class="field"><label>${html(tr("amount"))}</label><input id="teacherRateAmount" type="number" min="0" step="1" required /></div><div class="field"><label>${html(tr("group"))}</label><select id="teacherRateGroup"><option value="">${html(tr("all"))}</option>${groups.map((group) => `<option value="${attr(group.id)}">${html(group.name)}</option>`).join("")}</select></div><div class="field"><label>${html(tr("validFrom"))}</label><input id="teacherRateFrom" type="date" value="${attr(todayIso())}" required /></div><div class="field"><label>${html(tr("validUntil"))}</label><input id="teacherRateUntil" type="date" /></div><button class="primary-button" type="submit" ${drawer.saving ? "disabled" : ""}>${faIcon("fa-plus")} ${html(tr("addTeacherRate"))}</button></form></section>` : ""}<section class="teacher-drawer-section"><div class="drawer-section-header"><h3>${html(tr("upcomingLessons"))}</h3></div><div class="teacher-upcoming-list">${lessons.map((lesson) => `<div><span class="teacher-lesson-date">${html(lesson.date)}</span><span><strong>${html(lesson.groupName)}</strong><small>${html(lesson.time)} · ${html(lesson.subject || "")}</small></span></div>`).join("") || `<p class="card-subtitle">${html(tr("noUpcomingLessons"))}</p>`}</div></section></div>`;
}

function teacherAccessTab() {
  const teacher = state.teacherDrawer.teacher || {};
  return `<div class="drawer-stack"><div class="teacher-access-summary"><div><span>${faIcon("fa-shield-halved")}</span><div><strong>${html(tr("portalAccess"))}</strong><small>${html(teacher.username || tr("not_granted"))}</small></div></div>${teacherAccessBadge(teacher)}</div>${teacher.hasAccess ? `<form class="teacher-password-form" onsubmit="resetTeacherPassword(event)"><h3>${html(tr("resetPassword"))}</h3><div class="field"><label>${html(tr("newPassword"))}</label><input id="teacherResetPassword" type="password" minlength="8" autocomplete="new-password" required /></div><div class="field"><label>${html(tr("confirmPassword"))}</label><input id="teacherResetPasswordConfirm" type="password" minlength="8" autocomplete="new-password" required /></div><button class="primary-button" type="submit" ${state.teacherDrawer.saving ? "disabled" : ""}>${html(state.teacherDrawer.saving ? tr("saving") : tr("resetPassword"))}</button></form>` : `<button class="primary-button" type="button" onclick="editTeacherFromDrawer()">${faIcon("fa-key")} ${html(tr("createAccess"))}</button>`}</div>`;
}

async function openTeacherDrawer(teacherId, initialTab = "overview") {
  state.teacherDrawer = { teacherId, tab: initialTab, loading: true, saving: false, teacher: teacherById(teacherId), groups: [], workingHours: [], upcomingLessons: [], rateRules: [] };
  render();
  try {
    const [result, rateResult] = await Promise.all([
      api(`/api/teachers/${encodeURIComponent(teacherId)}`),
      state.role === "admin" ? api("/api/finance/teacher-rate-rules") : Promise.resolve({ teacherRateRules: [] }),
    ]);
    if (!state.teacherDrawer || state.teacherDrawer.teacherId !== teacherId) return;
    Object.assign(state.teacherDrawer, result, {
      loading: false,
      rateRules: (rateResult.teacherRateRules || []).filter((rule) => rule.teacherId === teacherId),
    });
    render();
  } catch (error) {
    state.teacherDrawer = null;
    showToast(errorMessage(error));
  }
}

function closeTeacherDrawer() {
  state.teacherDrawer = null;
  render();
}

function editTeacherFromDrawer() {
  const teacherId = state.teacherDrawer?.teacherId;
  if (!teacherId) return;
  state.teacherDrawer = null;
  openEditModal("teacher", teacherId);
}

function setTeacherDrawerTab(tab) {
  if (!state.teacherDrawer) return;
  state.teacherDrawer.tab = tab;
  render();
}

async function refreshTeacherDrawer() {
  if (!state.teacherDrawer) return;
  const teacherId = state.teacherDrawer.teacherId;
  const tab = state.teacherDrawer.tab;
  const [result, rateResult] = await Promise.all([
    api(`/api/teachers/${encodeURIComponent(teacherId)}`),
    state.role === "admin" ? api("/api/finance/teacher-rate-rules") : Promise.resolve({ teacherRateRules: [] }),
  ]);
  if (!state.teacherDrawer || state.teacherDrawer.teacherId !== teacherId) return;
  Object.assign(state.teacherDrawer, result, {
    tab,
    loading: false,
    saving: false,
    rateRules: (rateResult.teacherRateRules || []).filter((rule) => rule.teacherId === teacherId),
  });
}

async function addTeacherWorkingHour(event) {
  event.preventDefault();
  if (!state.teacherDrawer || state.teacherDrawer.saving) return;
  const payload = { teacherId: state.teacherDrawer.teacherId, weekday: val("teacherWeekday"), startTime: val("teacherStartTime"), endTime: val("teacherEndTime") };
  state.teacherDrawer.saving = true;
  render();
  try {
    await api("/api/teacher-working-hours", { method: "POST", body: JSON.stringify(payload) });
    await refreshTeacherDrawer();
    showToast(tr("saved"));
    render();
  } catch (error) {
    if (state.teacherDrawer) state.teacherDrawer.saving = false;
    showToast(errorMessage(error));
  }
}

