function applyStudentBalance(studentId, balance, studentPatch = {}) {
  if (!state.data) return;
  const nextDebt = balance < 0 ? Math.round(Math.abs(balance)) : 0;
  const dashboardDebtors = state.data.dashboard.debtors || [];
  const previousStudent = studentById(studentId) || dashboardDebtors.find((student) => student.id === studentId) || null;
  const previousDebt = Number(previousStudent?.debt || 0);
  if (state.lazyLoaded.students) {
    state.data.students = (state.data.students || []).map((student) =>
      student.id === studentId ? { ...student, ...studentPatch, balance, debt: nextDebt } : student,
    );
    const updatedStudent = studentById(studentId);
    state.data.dashboard.debtors = (state.data.students || []).filter((student) => Number(student.debt || 0) > 0);
    state.data.dashboard.stats.debtTotal = (state.data.students || []).reduce((sum, student) => sum + Number(student.debt || 0), 0);
    if (state.drawer?.studentId === studentId && updatedStudent) {
      state.drawer.student = { ...updatedStudent, ...studentPatch, balance, debt: nextDebt };
      state.drawer.balance = balance;
    }
    return;
  }
  const nextStudent = { ...(previousStudent || {}), ...studentPatch, id: studentId, balance, debt: nextDebt };
  state.data.dashboard.debtors = dashboardDebtors.filter((student) => student.id !== studentId);
  if (nextDebt > 0) state.data.dashboard.debtors = [nextStudent, ...state.data.dashboard.debtors];
  state.data.dashboard.stats.debtTotal = Number(state.data.dashboard.stats.debtTotal || 0) - previousDebt + nextDebt;
  if (state.drawer?.studentId === studentId) {
    state.drawer.student = nextStudent;
    state.drawer.balance = balance;
  }
}

function syncCreatedEntity(type, entity, payload = {}) {
  if (!state.data || !entity) return;
  const stats = state.data.dashboard?.stats || {};
  if (type === "teacher") {
    if (state.lazyLoaded.teachers) state.data.teachers = upsertById(state.data.teachers || [], entity);
    return;
  }
  if (type === "student") {
    const student = enrichStudent(entity);
    if (state.lazyLoaded.students) state.data.students = upsertById(state.data.students || [], student);
    stats.students = Number(stats.students || 0) + 1;
    if (Number(student.debt || 0) > 0) {
      state.data.dashboard.debtors = upsertById(state.data.dashboard.debtors || [], student);
      stats.debtTotal = Number(stats.debtTotal || 0) + Number(student.debt || 0);
    }
    return;
  }
  if (type === "group") {
    const group = enrichGroup(entity);
    if (state.lazyLoaded.groups) state.data.groups = upsertById(state.data.groups || [], group);
    stats.groups = Number(stats.groups || 0) + 1;
    return;
  }
  if (type === "lesson") {
    const lesson = enrichLesson(entity);
    if (state.lazyLoaded.lessons) state.data.lessons = upsertById(state.data.lessons || [], lesson);
    state.calendarLoadedDate = "";
    if (lesson.date === todayIso()) {
      stats.lessonsToday = Number(stats.lessonsToday || 0) + 1;
      state.data.dashboard.lessons = upsertById(state.data.dashboard.lessons || [], lesson);
    }
    return;
  }
  if (type === "payment") {
    if (state.lazyLoaded.payments) state.data.payments = upsertById(state.data.payments || [], entity);
    if (!entity.reused) stats.revenueToday = Number(stats.revenueToday || 0) + Number(entity.amount || 0);
    if (entity.studentId && entity.balance !== undefined) applyStudentBalance(entity.studentId, Number(entity.balance || 0));
    return;
  }
  if (type === "message") {
    if (state.lazyLoaded.messages) state.data.messages = upsertById(state.data.messages || [], entity);
    state.data.dashboard.messages = upsertById(state.data.dashboard.messages || [], entity).slice(0, 8);
    stats.queuedMessages = Number(stats.queuedMessages || 0) + (entity.status === "queued" ? 1 : 0);
    return;
  }
  if (type === "lead") {
    if (state.lazyLoaded.leads) state.data.leads = upsertById(state.data.leads || [], entity);
    return;
  }
}

function syncUpdatedEntity(type, entity) {
  if (!state.data || !entity) return;
  if (type === "teacher") {
    state.data.teachers = (state.data.teachers || []).map((teacher) => (teacher.id === entity.id ? entity : teacher));
    if (state.teacherDrawer?.teacherId === entity.id) state.teacherDrawer.teacher = { ...(state.teacherDrawer.teacher || {}), ...entity };
    return;
  }
  if (type === "student") {
    const student = enrichStudent(entity);
    state.data.students = (state.data.students || []).map((item) => (item.id === student.id ? student : item));
    state.data.dashboard.debtors = (state.data.dashboard.debtors || []).filter((item) => item.id !== student.id);
    if (Number(student.debt || 0) > 0) state.data.dashboard.debtors = upsertById(state.data.dashboard.debtors || [], student);
    if (state.drawer?.studentId === student.id) state.drawer.student = { ...(state.drawer.student || {}), ...student };
    return;
  }
  if (type === "group") {
    const group = enrichGroup(entity);
    state.data.groups = (state.data.groups || []).map((item) => (item.id === group.id ? group : item));
    state.data.students = (state.data.students || []).map((student) => (student.groupId === group.id ? { ...student, groupName: group.name } : student));
    state.data.lessons = (state.data.lessons || []).map((lesson) => (lesson.groupId === group.id ? enrichLesson({ ...lesson, groupName: group.name, subject: group.subject, room: group.room, teacherId: group.teacherId, teacherName: group.teacherName }) : lesson));
    state.data.dashboard.lessons = (state.data.dashboard.lessons || []).map((lesson) => (lesson.groupId === group.id ? enrichLesson({ ...lesson, groupName: group.name, subject: group.subject, room: group.room, teacherId: group.teacherId, teacherName: group.teacherName }) : lesson));
    if (state.groupDrawer?.groupId === group.id) state.groupDrawer.group = { ...(state.groupDrawer.group || {}), ...group };
    state.calendarLoadedDate = "";
    return;
  }
  if (type === "lesson") {
    const lesson = enrichLesson(entity);
    state.data.lessons = upsertById(state.data.lessons || [], lesson);
    state.data.dashboard.lessons = (state.data.dashboard.lessons || []).map((item) => (item.id === lesson.id ? lesson : item));
    state.calendarLoadedDate = "";
    return;
  }
  if (type === "payment") {
    state.data.payments = (state.data.payments || []).map((payment) => (payment.id === entity.id ? entity : payment));
    if (entity.previousStudentId && entity.previousStudentId !== entity.studentId && entity.previousBalance !== null) {
      applyStudentBalance(entity.previousStudentId, Number(entity.previousBalance || 0));
    }
    if (entity.studentId && entity.balance !== undefined) applyStudentBalance(entity.studentId, Number(entity.balance || 0));
  }
}

function mutationRefreshKeys(type) {
  return {
    teacher: ["teachers", "groups", "lessons"],
    student: ["students"],
    group: ["groups", "students", "lessons"],
    lesson: ["lessons"],
    payment: ["payments", "students", "messages"],
    message: ["messages"],
    lead: ["leads"],
  }[type] || [];
}

