async function submitTransaction(event, type) {
  event.preventDefault();
  if (!state.drawer) return;
  if (state.drawer.saving) return;
  const studentId = state.drawer.studentId;
  const amount = Number(val("walletAmount"));
  const description = val("walletDescription") || (type === "payment" ? tr("paymentNotePlaceholder") : tr("chargeNotePlaceholder"));
  const method = val("walletMethod") || "cash";
  try {
    state.drawer.saving = true;
    render();
    const result = await api(`/api/students/${encodeURIComponent(studentId)}/transactions`, {
      method: "POST",
      body: JSON.stringify({ type, amount, description, method, idempotencyKey: state.drawer.transactionIdempotencyKey || createIdempotencyKey() }),
    });
    if (!state.drawer || state.drawer.studentId !== studentId) return;
    state.drawer.saving = false;
    state.drawer.form = null;
    state.drawer.transactionIdempotencyKey = "";
    state.drawer.student = result.student;
    state.drawer.balance = Number(result.balance || 0);
    state.drawer.ledger = result.ledger || [];
    if (result.payment && state.data) {
      state.data.payments = [result.payment, ...state.data.payments.filter((payment) => payment.id !== result.payment.id)];
      if (!result.payment.reused) state.data.dashboard.stats.revenueToday += Number(result.payment.amount || 0);
    }
    applyStudentBalance(studentId, state.drawer.balance, result.student);
    showToast(type === "payment" ? tr("paymentSaved") : tr("chargeSaved"));
    backgroundRefresh(["students", "payments"], true);
    render();
  } catch (error) {
    if (state.drawer) state.drawer.saving = false;
    render();
    showToast(errorMessage(error));
  }
}

