function leadDragStart(event) {
  const card = event.currentTarget;
  const column = card.closest(".kanban-column");
  const leadId = card.dataset.leadId;
  state.dragLead = {
    id: leadId,
    fromStage: column?.dataset.stageId || column?.dataset.stage || "",
  };
  event.dataTransfer.effectAllowed = "move";
  event.dataTransfer.setData("text/plain", leadId);
  card.classList.add("dragging");
}

function leadDragEnd(event) {
  event.currentTarget.classList.remove("dragging");
  state.dragLead = null;
  clearLeadDropIndicators();
}

function leadDragOver(event) {
  event.preventDefault();
  event.dataTransfer.dropEffect = "move";
  const column = event.currentTarget.closest(".kanban-column");
  if (column) column.classList.add("drag-over");
}

function leadDragLeave(event) {
  const column = event.currentTarget.closest(".kanban-column");
  if (column && !column.contains(event.relatedTarget)) column.classList.remove("drag-over");
}

async function changeLeadStage(leadId, stage) {
  if (!leadId || !stage) return null;
  const currentLead = (state.data?.leads || []).find((lead) => lead.id === leadId);
  if (currentLead && leadStage(currentLead) === stage) return currentLead;
  state.leadStageSaving = leadId;
  render();
  try {
    const updatedLead = await api(`/api/leads/${encodeURIComponent(leadId)}/stage`, {
      method: "PATCH",
      body: JSON.stringify({ stage }),
    });
    state.data.leads = state.data.leads.map((lead) => (lead.id === updatedLead.id ? updatedLead : lead));
    state.leadStageSaving = "";
    showToast(tr("leadMoved"));
    backgroundRefresh(["leads"], false);
    render();
    return updatedLead;
  } catch (error) {
    state.leadStageSaving = "";
    render();
    throw error;
  }
}

async function handleLeadStageSelect(leadId, stage) {
  try {
    await changeLeadStage(leadId, stage);
  } catch (error) {
    showToast(errorMessage(error));
    render();
  }
}

async function leadDrop(event) {
  event.preventDefault();
  const column = event.currentTarget.closest(".kanban-column");
  const leadId = event.dataTransfer.getData("text/plain") || state.dragLead?.id;
  const stage = column?.dataset.stageId || column?.dataset.stage || "";
  clearLeadDropIndicators();
  if (!leadId || !stage || state.dragLead?.fromStage === stage) return;
  try {
    await changeLeadStage(leadId, stage);
  } catch (error) {
    showToast(errorMessage(error));
  }
}

function openLessonPopover(event, lessonId) {
  event.stopPropagation();
  const rect = event.currentTarget.getBoundingClientRect();
  const popoverWidth = 260;
  const left = Math.min(rect.right + 8, Math.max(16, window.innerWidth - popoverWidth - 16));
  const top = Math.min(rect.top, Math.max(16, window.innerHeight - 220));
  state.calendarPopover = { id: lessonId, left, top };
  render();
}

function closeLessonPopover() {
  if (!state.calendarPopover) return;
  state.calendarPopover = null;
  render();
}

async function openCalendarAttendance(lessonId) {
  await loadDataKeys(["lessons", "students", "groups"]).catch(() => {});
  const realLesson = lessonById(lessonId);
  state.calendarPopover = null;
  if (realLesson) {
    if (realLesson.date > todayIso()) {
      showToast(tr("futureAttendanceLocked"));
      render();
      return;
    }
    openAttendance(lessonId);
    return;
  }
  const scheduleLesson = (state.calendarLessons || []).find((lesson) => lesson.id === lessonId);
  if (scheduleLesson && calendarLessonDate(scheduleLesson) > todayIso()) {
    showToast(tr("futureAttendanceLocked"));
    render();
    return;
  }
  const canMaterialize = scheduleLesson && (state.role === "admin" || (state.role === "teacher" && scheduleLesson.teacher_id === state.userId));
  if (!scheduleLesson || !canMaterialize) {
    showToast(tr("lessonNotFound"));
    render();
    return;
  }
  const group = (state.data.groups || []).find((item) => item.id === scheduleLesson.group_id);
  if (!group) {
    showToast(tr("groupNotFound"));
    render();
    return;
  }
  try {
    state.isSaving = true;
    render();
    const created = await api("/api/lesson-occurrences", {
      method: "POST",
      body: JSON.stringify({
        groupId: group.id,
        scheduleId: scheduleLesson.schedule_id,
        time: `${scheduleLesson.start_time} - ${scheduleLesson.end_time}`,
        date: calendarLessonDate(scheduleLesson),
      }),
    });
    const lesson = enrichLesson(created);
    state.data.lessons = upsertById(state.data.lessons || [], lesson);
    state.calendarLoadedDate = "";
    state.isSaving = false;
    showToast(tr("attendanceOpened"));
    backgroundRefresh(["lessons"], true);
    await openAttendance(lesson.id);
  } catch (error) {
    state.isSaving = false;
    showToast(errorMessage(error));
    render();
  }
}

async function cancelLesson(lessonId) {
  if (!lessonId || state.role !== "admin") return;
  const reason = typeof window !== "undefined" && typeof window.prompt === "function"
    ? window.prompt(tr("cancellationReasonPrompt"), "")
    : "";
  if (!String(reason || "").trim()) return;
  try {
    const lesson = await api(`/api/lessons/${encodeURIComponent(lessonId)}/cancel`, {
      method: "POST",
      body: JSON.stringify({ reason: String(reason).trim() }),
    });
    syncUpdatedEntity("lesson", lesson);
    state.calendarPopover = null;
    state.calendarLoadedDate = "";
    showToast(tr("lessonCancelled"));
    backgroundRefresh(["lessons", "attendanceRecords"], true);
    render();
  } catch (error) {
    showToast(errorMessage(error));
  }
}

async function restoreLesson(lessonId) {
  if (!lessonId || state.role !== "admin") return;
  try {
    const lesson = await api(`/api/lessons/${encodeURIComponent(lessonId)}/restore`, {
      method: "POST",
      body: "{}",
    });
    syncUpdatedEntity("lesson", lesson);
    state.calendarPopover = null;
    state.calendarLoadedDate = "";
    showToast(tr("lessonRestored"));
    backgroundRefresh(["lessons"], true);
    render();
  } catch (error) {
    showToast(errorMessage(error));
  }
}

function attendanceFinancePanel(lesson) {
  if (state.role !== "admin" || lesson.status !== "completed") return "";
  const preview = state.lessonFinancePreview;
  const status = lesson.financialStatus || preview?.financialStatus || "unposted";
  const blockers = preview?.blockers || [];
  const settlement = preview?.settlement || null;
  const statusText = status === "posted" ? tr("financialPosted") : status === "pending" ? tr("financialPending") : tr(status);
  return `<section class="attendance-finance-panel"><div class="attendance-finance-header"><div><strong>${html(statusText)}</strong>${preview?.totals ? `<span>${html(`${money(preview.totals.studentCharges || 0)} · ${tr("teacher")}: ${money(preview.totals.teacherAccrual || 0)}`)}</span>` : ""}</div><span class="status ${statusClass(status)}">${html(tr(status))}</span></div>${blockers.length ? `<ul>${blockers.map((blocker) => `<li>${html(financeBlockerMessage(blocker))}</li>`).join("")}</ul>` : ""}<div class="attendance-finance-actions">${preview?.readyToConfirm ? `<button class="primary-button" type="button" onclick="confirmLessonFinance()" ${state.isSaving ? "disabled" : ""}>${faIcon("fa-shield-check")} ${html(tr("confirmFinance"))}</button>` : ""}${status === "posted" && settlement ? `<button class="ghost-button danger" type="button" onclick="reverseLessonFinance()" ${state.isSaving ? "disabled" : ""}>${faIcon("fa-rotate-left")} ${html(tr("reverseFinance"))}</button>` : ""}${status !== "posted" ? `<button class="ghost-button" type="button" onclick="reopenCompletedLesson()" ${state.isSaving ? "disabled" : ""}>${faIcon("fa-door-open")} ${html(tr("reopenCompletedLesson"))}</button>` : ""}</div></section>`;
}

function financeBlockerMessage(blocker) {
  const key = `financeBlocker_${blocker?.code || ""}`;
  const localized = tr(key);
  return localized !== key ? localized : blocker?.message || tr("financeNotReady");
}

function attendanceReasonLabel(reason) {
  if (!reason?.isSystem) return reason?.name || "";
  return tr(reason.code) || reason.name || reason.code;
}

function attendanceBody() {
  const lesson = lessonById(state.modal.lessonId);
  if (!lesson) return emptyInlineState("fa-triangle-exclamation", tr("lessonNotFound"));
  const students = state.attendanceStudents || [];
  const alertCount = attendanceAlertCount(students);
  const readOnly = lesson.date > todayIso() || lesson.status === "cancelled" || (lesson.status === "completed" && state.role !== "admin");
  const statusCounts = { present: 0, absent: 0, late: 0, excused: 0 };
  let marked = 0;
  students.forEach((student) => {
    const status = state.attendanceDraft[student.id];
    if (statusCounts[status] !== undefined) {
      statusCounts[status] += 1;
      marked += 1;
    }
  });
  const remaining = students.length - marked;
  const lockMessage = lesson.date > todayIso()
    ? tr("futureAttendanceLocked")
    : lesson.status === "cancelled"
      ? tr("cancelledAttendanceLocked")
      : lesson.status === "completed" && state.role !== "admin"
        ? tr("attendanceLocked")
        : "";
  return `<div class="attendance-context"><div><span>${html(lesson.date)}</span><strong>${html(lesson.time)} · ${html(lesson.groupName)}</strong><small>${html([lesson.subject, lesson.room].filter(Boolean).join(" · "))}</small></div><span class="status ${statusClass(lesson.status)}">${html(tr(lesson.status))}</span></div>
  ${lockMessage ? `<div class="attendance-lock-notice">${faIcon("fa-lock")} <span>${html(lockMessage)}</span></div>` : ""}
  <div class="attendance-toolbar"><div><strong>${html(formatTemplate("attendanceProgress", { marked, total: students.length }))}</strong><span>${html(remaining ? formatTemplate("attendanceRemaining", { count: remaining }) : tr("attendanceComplete"))}</span></div><button class="ghost-button" type="button" onclick="markAllAttendancePresent()" ${readOnly || !students.length ? "disabled" : ""}>${faIcon("fa-check-double")} ${html(tr("markAllPresent"))}</button></div>
  <div class="attendance-summary">${["present", "absent", "late", "excused"].map((status) => `<span class="attendance-summary-${status}"><strong>${html(statusCounts[status])}</strong>${html(tr(status))}</span>`).join("")}</div>
  <div class="attendance-list">
    ${students.map((student) => {
      const current = state.attendanceDraft[student.id] || "";
      const matchingReasons = (state.attendanceReasons || []).filter((reason) => reason.attendanceStatus === current && reason.isActive);
      const selectedReasonId = state.attendanceReasonDraft[student.id] || "";
      const hasSelectedReason = matchingReasons.some((reason) => reason.id === selectedReasonId);
      const historicalOption = selectedReasonId && !hasSelectedReason
        ? `<option value="${attr(selectedReasonId)}" selected>${html(student.attendanceReasonName || student.attendanceReasonCode || tr("historicalReason"))} · ${html(tr("historicalReason"))}</option>`
        : "";
      return `<div class="attendance-row"><div class="mini-avatar">${html(initials(student.name))}</div><div><div class="row-title">${html(student.name)}</div><div class="row-meta">${html(student.parentName)}</div></div><div class="attendance-row-controls"><div class="segmented">${["present", "absent", "late", "excused"].map((status) => `<button class="segment ${current === status ? "active" : ""}" onclick="setAttendance('${jsString(student.id)}', '${jsString(status)}')" ${readOnly ? "disabled" : ""}>${html(tr(status))}</button>`).join("")}</div>${current ? `<select class="attendance-reason-select" aria-label="${attr(tr("attendanceReason"))}" onchange="setAttendanceReason('${jsString(student.id)}', this.value)" ${readOnly ? "disabled" : ""}>${historicalOption}${matchingReasons.map((reason) => `<option value="${attr(reason.id)}" ${reason.id === selectedReasonId ? "selected" : ""}>${html(attendanceReasonLabel(reason))} · ${html(`${Number(reason.chargePercent || 0)}%`)}</option>`).join("")}</select>` : ""}<input class="attendance-student-note" value="${attr(state.attendanceNoteDraft[student.id] || "")}" maxlength="500" placeholder="${attr(tr("attendanceStudentNotePlaceholder"))}" aria-label="${attr(tr("attendanceStudentNote"))}" oninput="setAttendanceNote('${jsString(student.id)}', this.value)" ${readOnly ? "disabled" : ""} /></div></div>`;
    }).join("") || emptyInlineState("fa-users", tr("students"))}
  </div><section class="attendance-lesson-details"><h3>${html(tr("attendanceLessonDetails"))}</h3><div class="attendance-lesson-fields"><div class="field"><label>${html(tr("lessonTopic"))}</label><input value="${attr(state.attendanceLessonDraft.topic || "")}" maxlength="500" oninput="setAttendanceLessonField('topic', this.value)" ${readOnly ? "disabled" : ""} /></div><div class="field"><label>${html(tr("homework"))}</label><textarea maxlength="2000" oninput="setAttendanceLessonField('homework', this.value)" ${readOnly ? "disabled" : ""}>${html(state.attendanceLessonDraft.homework || "")}</textarea></div><div class="field"><label>${html(tr("note"))}</label><textarea maxlength="2000" oninput="setAttendanceLessonField('note', this.value)" ${readOnly ? "disabled" : ""}>${html(state.attendanceLessonDraft.note || "")}</textarea></div></div></section>${attendanceFinancePanel(lesson)}${lesson.status === "completed" && state.role === "admin" ? `<div class="field attendance-correction-reason"><label>${html(tr("correctionReason"))}</label><textarea id="attendanceCorrectionReason" maxlength="500" placeholder="${attr(tr("correctionReason"))}" oninput="setAttendanceCorrectionReason(this.value)">${html(state.attendanceCorrectionReason || "")}</textarea></div>` : ""}<div class="modal-footer modal-footer-inline attendance-actions">
    <div class="attendance-save-row">
      <button class="ghost-button" onclick="closeAppModal()" ${state.isSaving || state.attendanceAlertSending ? "disabled" : ""}>${html(tr("cancel"))}</button>
      <button class="primary-button" onclick="saveAttendance()" ${state.isSaving || readOnly || remaining > 0 ? "disabled" : ""}>${html(state.isSaving ? tr("saving") : tr("save"))}</button>
    </div>
    <button class="attendance-alert-button" onclick="openAttendanceAlertConfirm()" ${alertCount > 0 && !state.isSaving && !state.attendanceAlertSending ? "" : "disabled"}>
      ${faIcon("fa-telegram", "fa-brands", "telegram-blue-icon")} ${html(tr("sendAttendanceAlerts"))}
    </button>
  </div>`;
}

function attendanceAlertCount(students = null) {
  const rows = students || state.attendanceStudents || [];
  return rows.filter((student) => ["absent", "late"].includes(state.attendanceDraft[student.id] || "")).length;
}

function openAttendanceAlertConfirm() {
  if (!state.modal || state.modal.type !== "attendance") return;
  const count = attendanceAlertCount();
  if (!count) return;
  state.attendanceAlertConfirm = {
    lessonId: state.currentLesson?.id || state.modal.lessonId,
    count,
  };
  render();
}

function closeAttendanceAlertConfirm() {
  state.attendanceAlertConfirm = null;
  state.attendanceAlertSending = false;
  render();
}

function attendanceAlertModal() {
  if (!state.attendanceAlertConfirm) return "";
  const count = state.attendanceAlertConfirm.count;
  const message = tr("attendanceAlertConfirm").replace("{count}", count);
  return `<div class="modal-backdrop" onclick="closeAttendanceAlertConfirm()"><div class="modal attendance-alert-modal" onclick="event.stopPropagation()">
    <div class="modal-header"><h2 class="card-title">${html(tr("sendAttendanceAlerts"))}</h2><button class="icon-button" aria-label="${attr(tr("cancel"))}" onclick="closeAttendanceAlertConfirm()">${faIcon("fa-xmark")}</button></div>
    <div class="modal-body"><p class="stage-confirm-text">${html(message)}</p></div>
    <div class="modal-footer"><button class="ghost-button" type="button" onclick="closeAttendanceAlertConfirm()">${html(tr("cancel"))}</button><button class="primary-button" type="button" onclick="sendAttendanceAlerts()" ${state.attendanceAlertSending ? "disabled" : ""}>${html(state.attendanceAlertSending ? tr("saving") : tr("send"))}</button></div>
  </div></div>`;
}

function deleteConfirmModal() {
  if (!state.deleteConfirm) return "";
  const confirm = state.deleteConfirm;
  const title = { teacher: tr("archiveTeacher"), student: tr("archiveStudent"), group: tr("archiveGroup"), payment: tr("deletePayment") }[confirm.type] || tr("deleteConfirmTitle");
  const entity = confirm.type === "teacher" ? teacherById(confirm.id) : confirm.type === "student" ? studentById(confirm.id) : confirm.type === "group" ? groupById(confirm.id) : confirm.type === "payment" ? paymentById(confirm.id) : null;
  const entityName = entity?.name || entity?.studentName || "";
  return `<div class="modal-backdrop" onclick="closeDeleteConfirm()"><div class="modal delete-confirm-modal" onclick="event.stopPropagation()">
    <div class="modal-header"><h2 class="card-title">${html(title)}</h2><button class="icon-button" aria-label="${attr(tr("cancel"))}" onclick="closeDeleteConfirm()">${faIcon("fa-xmark")}</button></div>
    <div class="modal-body"><p class="stage-confirm-text">${html(entityName ? `${entityName}. ${tr(confirm.type === "teacher" ? "archiveTeacherConfirm" : confirm.type === "student" ? "archiveStudentConfirm" : confirm.type === "group" ? "archiveGroupConfirm" : "deleteConfirmText")}` : tr(confirm.type === "teacher" ? "archiveTeacherConfirm" : confirm.type === "student" ? "archiveStudentConfirm" : confirm.type === "group" ? "archiveGroupConfirm" : "deleteConfirmText"))}</p>${["student", "group"].includes(confirm.type) ? `<div class="field archive-reason-field"><label>${html(tr("archiveReason"))}</label><textarea id="${confirm.type === "student" ? "studentArchiveReason" : "groupArchiveReason"}" placeholder="${attr(tr(confirm.type === "student" ? "archiveReasonPlaceholder" : "groupArchiveReasonPlaceholder"))}"></textarea></div>` : ""}</div>
    <div class="modal-footer"><button class="ghost-button" type="button" onclick="closeDeleteConfirm()" ${confirm.saving ? "disabled" : ""}>${html(tr("cancel"))}</button><button class="stage-delete-button" type="button" onclick="confirmDeleteEntity()" ${confirm.saving ? "disabled" : ""}>${html(confirm.saving ? tr("saving") : tr(confirm.type === "teacher" ? "archiveTeacher" : confirm.type === "student" ? "archiveStudent" : confirm.type === "group" ? "archiveGroup" : "confirmDelete"))}</button></div>
  </div></div>`;
}

function closeDeleteConfirm() {
  state.deleteConfirm = null;
  render();
}

