function openPlatformTenantModal() {
  state.platformModal = { type: "tenant" };
  state.platformSaving = false;
  state.footerMenuOpen = false;
  render();
}

function openPlatformAdminModal(tenantId) {
  state.platformModal = { type: "admin", tenantId };
  state.platformSaving = false;
  state.footerMenuOpen = false;
  render();
}

function openPlatformTenantEditModal(tenantId) {
  state.platformModal = { type: "editTenant", tenantId };
  state.platformSaving = false;
  state.footerMenuOpen = false;
  render();
}

function closePlatformModal(event = null) {
  if (event && event.target && !event.target.classList.contains("modal-backdrop")) return;
  if (state.platformSaving) return;
  state.platformModal = null;
  render();
}

async function savePlatformModal() {
  if (!state.platformModal || state.platformSaving) return;
  if (!reportModalValidity()) return;
  const modal = state.platformModal;
  const payload =
    modal.type === "tenant"
      ? {
          name: val("platformTenantName"),
          domain: val("platformTenantDomain"),
        }
      : modal.type === "editTenant"
        ? {
            name: val("platformTenantName"),
            status: val("platformTenantStatus"),
            plan: val("platformTenantPlan"),
            suspendedReason: val("platformTenantSuspensionReason"),
          }
      : {
          name: val("platformAdminName"),
          username: val("platformAdminUsername"),
          password: val("platformAdminPassword"),
        };
  state.platformSaving = true;
  render();
  try {
    if (modal.type === "tenant") {
      const tenant = await api("/api/platform/tenants", {
        method: "POST",
        body: JSON.stringify(payload),
      });
      state.platformTenants = upsertById(state.platformTenants || [], tenant).sort((a, b) => String(a.name).localeCompare(String(b.name), currentLocale()));
      await refreshPlatformTenants().catch(() => {});
      state.platformModal = null;
      state.platformSaving = false;
      showToast(tr("tenantCreated"));
      render();
      return;
    }

    if (modal.type === "editTenant") {
      const tenant = await api(`/api/platform/tenants/${encodeURIComponent(modal.tenantId)}`, {
        method: "PATCH",
        body: JSON.stringify(payload),
      });
      state.platformTenants = upsertById(state.platformTenants || [], tenant).sort((a, b) => String(a.name).localeCompare(String(b.name), currentLocale()));
      await refreshPlatformTenants().catch(() => {});
      state.platformModal = null;
      state.platformSaving = false;
      showToast(tr("centerUpdated"));
      render();
      return;
    }

    const user = await api(`/api/platform/tenants/${encodeURIComponent(modal.tenantId)}/users`, {
      method: "POST",
      body: JSON.stringify(payload),
    });
    state.platformCreatedAdmins = { ...(state.platformCreatedAdmins || {}), [modal.tenantId]: user };
    await refreshPlatformTenants().catch(() => {});
    state.platformModal = null;
    state.platformSaving = false;
    showToast(tr("adminCreated"));
    render();
  } catch (error) {
    state.platformSaving = false;
    showToast(errorMessage(error));
    render();
  }
}

async function switchTenantMode(tenantId) {
  if (!tenantId) {
    if (isTenantMode()) await exitTenantMode();
    return;
  }
  if (state.platformLoading || state.user?.activeTenantId === tenantId) return;
  state.platformLoading = true;
  render();
  try {
    const result = await api("/api/platform/switch-tenant", {
      method: "POST",
      body: JSON.stringify({ tenantId }),
    });
    setUser(result.user);
    state.page = "dashboard";
    state.platformLoading = false;
    await load();
    showToast(tr("tenantSwitched"));
  } catch (error) {
    state.platformLoading = false;
    showToast(errorMessage(error));
    render();
  }
}

async function exitTenantMode() {
  if (!isSuperAdminUser() || state.platformLoading) return;
  state.platformLoading = true;
  render();
  try {
    const result = await api("/api/platform/exit-tenant", { method: "POST", body: "{}" });
    setUser(result.user);
    state.page = "dashboard";
    state.data = null;
    state.lazyLoaded = {};
    state.lazyLoading = {};
    Object.keys(lazyPromises).forEach((key) => delete lazyPromises[key]);
    state.platformLoading = false;
    await load();
    showToast(tr("platformReturned"));
  } catch (error) {
    state.platformLoading = false;
    showToast(errorMessage(error));
    render();
  }
}

async function openModal(type, options = {}) {
  state.currentLesson = null;
  state.isSaving = false;
  state.attendanceDraft = {};
  state.attendanceOriginalDraft = {};
  state.attendanceReasonDraft = {};
  state.attendanceOriginalReasonDraft = {};
  state.attendanceNoteDraft = {};
  state.attendanceOriginalNoteDraft = {};
  state.attendanceLessonDraft = {};
  state.attendanceOriginalLessonDraft = {};
  state.attendanceCorrectionReason = "";
  state.attendanceReasons = [];
  state.lessonFinancePreview = null;
  state.attendanceAlertConfirm = null;
  state.attendanceAlertSending = false;
  state.deleteConfirm = null;
  state.footerMenuOpen = false;
  state.stageMenu = null;
  state.calendarPopover = null;
  const modalRequirements = {
    student: ["groups"],
    group: ["teachers"],
    lesson: ["groups", "teachers"],
    payment: ["students"],
  };
  const requirements = modalRequirements[type] || [];
  if (requirements.length) {
    try {
      await loadDataKeys(requirements);
    } catch (_error) {
      return;
    }
  }
  if (type === "message") {
    resetMessageModalState();
    state.messageSearchSeq += 1;
  }
  state.modal = { type, ...options, ...(type === "payment" ? { idempotencyKey: options.idempotencyKey || createIdempotencyKey() } : {}) };
  render();
}

async function openEditModal(type, id) {
  state.currentLesson = null;
  state.isSaving = false;
  state.attendanceDraft = {};
  state.attendanceOriginalDraft = {};
  state.attendanceReasonDraft = {};
  state.attendanceOriginalReasonDraft = {};
  state.attendanceReasons = [];
  state.lessonFinancePreview = null;
  state.attendanceAlertConfirm = null;
  state.attendanceAlertSending = false;
  state.deleteConfirm = null;
  state.footerMenuOpen = false;
  state.commandPaletteOpen = false;
  state.stageMenu = null;
  state.calendarPopover = null;
  const requirements = {
    teacher: ["teachers"],
    student: ["students", "groups"],
    group: ["groups", "teachers"],
    lesson: ["lessons", "groups", "teachers"],
    payment: ["payments", "students"],
  }[type] || [];
  try {
    await loadDataKeys(requirements);
  } catch (_error) {
    return;
  }
  if (type === "lesson") {
    try {
      const profile = await api(`/api/lessons/${encodeURIComponent(id)}`);
      if (profile.lesson) syncUpdatedEntity("lesson", profile.lesson);
    } catch (error) {
      showToast(errorMessage(error));
      return;
    }
  }
  const entity = type === "teacher" ? teacherById(id) : type === "student" ? studentById(id) : type === "group" ? groupById(id) : type === "lesson" ? lessonById(id) : type === "payment" ? paymentById(id) : null;
  if (!entity) {
    showToast(tr("noData"));
    return;
  }
  state.modal = { type, mode: "edit", id };
  render();
}

function openDeleteConfirm(type, id) {
  state.footerMenuOpen = false;
  state.commandPaletteOpen = false;
  state.stageMenu = null;
  state.calendarPopover = null;
  state.deleteConfirm = { type, id, saving: false };
  render();
}

function removeEntityFromState(type, id, deleted = null) {
  if (!state.data) return;
  if (type === "teacher") {
    state.data.teachers = (state.data.teachers || []).map((teacher) => (teacher.id === id ? { ...teacher, ...deleted } : teacher));
    if (state.teacherDrawer?.teacherId === id) state.teacherDrawer = null;
    return;
  }
  if (type === "student") {
    state.data.students = (state.data.students || []).map((student) => student.id === id ? { ...student, ...(deleted || {}), status: "left" } : student);
    state.data.dashboard.debtors = (state.data.dashboard.debtors || []).filter((student) => student.id !== id);
    if (state.drawer?.studentId === id) state.drawer = null;
    state.data.dashboard.stats.students = Math.max(0, Number(state.data.dashboard.stats.students || 0) - 1);
    return;
  }
  if (type === "group") {
    state.data.groups = (state.data.groups || []).map((group) => group.id === id ? { ...group, ...(deleted || {}), active: false, status: "archived" } : group);
    if (state.groupDrawer?.groupId === id) state.groupDrawer = null;
    state.data.dashboard.stats.groups = Math.max(0, Number(state.data.dashboard.stats.groups || 0) - 1);
    return;
  }
  if (type === "payment") {
    state.data.payments = (state.data.payments || []).filter((payment) => payment.id !== id);
    if (deleted?.studentId && deleted.balance !== undefined) applyStudentBalance(deleted.studentId, Number(deleted.balance || 0));
  }
}

async function confirmDeleteEntity() {
  if (!state.deleteConfirm || state.deleteConfirm.saving) return;
  const { type, id } = state.deleteConfirm;
  state.deleteConfirm.saving = true;
  render();
  try {
    const deleted = await api(`/api/${type === "teacher" ? "teachers" : type === "student" ? "students" : type === "group" ? "groups" : "payments"}/${encodeURIComponent(id)}`, {
      method: "DELETE",
      body: JSON.stringify(type === "student" ? { reason: val("studentArchiveReason") } : type === "group" ? { reason: val("groupArchiveReason") } : {}),
    });
    removeEntityFromState(type, id, deleted);
    state.deleteConfirm = null;
    showToast(tr(type === "teacher" ? "teacherArchived" : type === "student" ? "studentArchived" : type === "group" ? "groupArchived" : "saved"));
    backgroundRefresh(mutationRefreshKeys(type), true);
    render();
  } catch (error) {
    if (state.deleteConfirm) state.deleteConfirm.saving = false;
    showToast(errorMessage(error));
    render();
  }
}

