async function openAttendance(lessonId) {
  if (!lessonId) return;
  try {
    await loadDataKeys(["lessons", "students"]);
  } catch (_error) {
    return;
  }
  const lesson = lessonById(lessonId);
  if (!lesson) return showToast(tr("lessonNotFound"));
  if (lesson.date > todayIso()) return showToast(tr("futureAttendanceLocked"));
  try {
    const [result, reasonsResult] = await Promise.all([
      api(`/api/lessons/${encodeURIComponent(lessonId)}/students`),
      api("/api/attendance-reasons"),
    ]);
    state.currentLesson = result.lesson ? { ...lesson, ...result.lesson } : lesson;
    if (result.lesson) syncUpdatedEntity("lesson", state.currentLesson);
    state.attendanceStudents = result.students || [];
    state.attendanceReasons = reasonsResult.attendanceReasons || [];
    state.attendanceDraft = Object.fromEntries(state.attendanceStudents.filter((student) => student.attendanceStatus).map((student) => [student.id, student.attendanceStatus]));
    state.attendanceOriginalDraft = Object.fromEntries(state.attendanceStudents.map((student) => [student.id, student.attendanceStatus || ""]));
    const defaultReasonCodes = { present: "present", absent: "absent_unexcused", late: "late", excused: "excused" };
    state.attendanceReasonDraft = Object.fromEntries(state.attendanceStudents.map((student) => {
      const reason = student.attendanceReasonId
        ? state.attendanceReasons.find((item) => item.id === student.attendanceReasonId)
        : state.attendanceReasons.find((item) => item.code === defaultReasonCodes[student.attendanceStatus]);
      return [student.id, student.attendanceReasonId || reason?.id || ""];
    }));
    state.attendanceOriginalReasonDraft = { ...state.attendanceReasonDraft };
    state.attendanceNoteDraft = Object.fromEntries(state.attendanceStudents.map((student) => [student.id, student.attendanceNote || ""]));
    state.attendanceOriginalNoteDraft = { ...state.attendanceNoteDraft };
    state.attendanceLessonDraft = { topic: lesson.topic || "", homework: lesson.homework || "", note: lesson.note || "" };
    state.attendanceOriginalLessonDraft = { ...state.attendanceLessonDraft };
    state.attendanceCorrectionReason = "";
    state.lessonFinancePreview = null;
    if (state.role === "admin" && lesson.status === "completed") {
      state.lessonFinancePreview = await api(`/api/lessons/${encodeURIComponent(lessonId)}/finance-preview`).catch(() => null);
    }
    state.modal = { type: "attendance", lessonId, financeIdempotencyKey: createIdempotencyKey() };
    render();
  } catch (error) {
    showToast(errorMessage(error));
  }
}

function setAttendance(studentId, status) {
  const lesson = state.currentLesson || lessonById(state.modal?.lessonId);
  if (lesson?.date > todayIso() || lesson?.status === "cancelled" || (lesson?.status === "completed" && state.role !== "admin")) return;
  state.attendanceDraft[studentId] = status;
  const defaults = { present: "present", absent: "absent_unexcused", late: "late", excused: "excused" };
  const reason = (state.attendanceReasons || []).find((item) => item.code === defaults[status] && item.isActive)
    || (state.attendanceReasons || []).find((item) => item.attendanceStatus === status && item.isActive);
  state.attendanceReasonDraft[studentId] = reason?.id || "";
  render();
}

function setAttendanceReason(studentId, reasonId) {
  const lesson = state.currentLesson || lessonById(state.modal?.lessonId);
  if (lesson?.status === "cancelled" || (lesson?.status === "completed" && state.role !== "admin")) return;
  state.attendanceReasonDraft[studentId] = reasonId;
}

function setAttendanceNote(studentId, note) {
  const lesson = state.currentLesson || lessonById(state.modal?.lessonId);
  if (lesson?.date > todayIso() || lesson?.status === "cancelled" || (lesson?.status === "completed" && state.role !== "admin")) return;
  state.attendanceNoteDraft[studentId] = String(note || "").slice(0, 500);
}

function setAttendanceLessonField(field, value) {
  const lesson = state.currentLesson || lessonById(state.modal?.lessonId);
  if (!["topic", "homework", "note"].includes(field) || lesson?.date > todayIso() || lesson?.status === "cancelled" || (lesson?.status === "completed" && state.role !== "admin")) return;
  const maxLength = field === "topic" ? 500 : 2000;
  state.attendanceLessonDraft[field] = String(value || "").slice(0, maxLength);
}

function setAttendanceCorrectionReason(value) {
  state.attendanceCorrectionReason = String(value || "").slice(0, 500);
}

function markAllAttendancePresent() {
  const lesson = state.currentLesson || lessonById(state.modal?.lessonId);
  if (!lesson || lesson.date > todayIso() || lesson.status === "cancelled" || (lesson.status === "completed" && state.role !== "admin")) return;
  const presentReason = (state.attendanceReasons || []).find((reason) => reason.code === "present" && reason.isActive)
    || (state.attendanceReasons || []).find((reason) => reason.attendanceStatus === "present" && reason.isActive);
  (state.attendanceStudents || []).forEach((student) => {
    state.attendanceDraft[student.id] = "present";
    state.attendanceReasonDraft[student.id] = presentReason?.id || "";
  });
  render();
}

function attendanceDraftChanged() {
  const lesson = state.currentLesson || lessonById(state.modal?.lessonId);
  if (!lesson) return false;
  const students = state.attendanceStudents || [];
  return students.some((student) =>
    (state.attendanceDraft[student.id] || "") !== (state.attendanceOriginalDraft[student.id] || "")
      || (state.attendanceReasonDraft[student.id] || "") !== (state.attendanceOriginalReasonDraft[student.id] || "")
      || (state.attendanceNoteDraft[student.id] || "") !== (state.attendanceOriginalNoteDraft[student.id] || ""),
  ) || ["topic", "homework", "note"].some((field) =>
    (state.attendanceLessonDraft[field] || "") !== (state.attendanceOriginalLessonDraft[field] || ""),
  );
}

function attendancePayload() {
  const lesson = state.currentLesson || lessonById(state.modal?.lessonId);
  if (!lesson) throw new Error(tr("lessonMissingRefresh"));
  const students = state.attendanceStudents || [];
  if (students.some((student) => !["present", "absent", "late", "excused"].includes(state.attendanceDraft[student.id]))) {
    throw new Error(tr("attendanceIncomplete"));
  }
  const records = students.map((student) => ({
    studentId: student.id,
    status: state.attendanceDraft[student.id],
    reasonId: state.attendanceReasonDraft[student.id],
    note: (state.attendanceNoteDraft[student.id] || "").trim(),
  }));
  return {
    lesson,
    records,
    correctionReason: state.attendanceCorrectionReason.trim(),
    topic: (state.attendanceLessonDraft.topic || "").trim(),
    homework: (state.attendanceLessonDraft.homework || "").trim(),
    lessonNote: (state.attendanceLessonDraft.note || "").trim(),
  };
}

async function persistAttendanceDraft() {
  const { lesson, records, correctionReason, topic, homework, lessonNote } = attendancePayload();
  if (lesson.status === "completed" && !attendanceDraftChanged()) return { skipped: true };
  const result = await api("/api/attendance", { method: "POST", body: JSON.stringify({ lessonId: lesson.id, records, correctionReason, topic, homework, lessonNote }) });
  if (result.dashboard && state.data) state.data.dashboard = result.dashboard;
  if (result.lesson) syncUpdatedEntity("lesson", result.lesson);
  if (state.data?.lessons) {
    state.data.lessons = state.data.lessons.map((item) => (item.id === lesson.id ? { ...item, status: "completed" } : item));
  }
  if (state.data?.dashboard?.lessons) {
    state.data.dashboard.lessons = state.data.dashboard.lessons.map((item) => (item.id === lesson.id ? { ...item, status: "completed" } : item));
  }
  state.calendarLoadedDate = "";
  state.attendanceOriginalDraft = Object.fromEntries(records.map((record) => [record.studentId, record.status]));
  state.attendanceOriginalReasonDraft = Object.fromEntries(records.map((record) => [record.studentId, record.reasonId || ""]));
  state.attendanceOriginalNoteDraft = Object.fromEntries(records.map((record) => [record.studentId, record.note || ""]));
  state.attendanceOriginalLessonDraft = { topic, homework, note: lessonNote };
  return result;
}

function val(id) {
  return document.getElementById(id)?.value?.trim() || "";
}

function isChecked(id) {
  return Boolean(document.getElementById(id)?.checked);
}

function reportModalValidity() {
  if (typeof document === "undefined" || !document.querySelector) return true;
  const modalElement = document.querySelector(".modal");
  if (!modalElement) return true;
  const invalid = modalElement.querySelector("input:invalid, select:invalid, textarea:invalid");
  if (!invalid) return true;
  if (typeof invalid.reportValidity === "function") invalid.reportValidity();
  if (typeof invalid.focus === "function") invalid.focus();
  return false;
}

async function saveModal() {
  if (state.isSaving) return;
  if (!state.modal) return;
  if (!reportModalValidity()) return;
  const type = state.modal.type;
  const isEdit = state.modal.mode === "edit";
  if (type === "teacher" && val("teacherPassword") !== val("teacherPasswordConfirm")) {
    showToast(tr("passwordMismatch"));
    return;
  }
  const basePayloads = {
    teacher: { name: val("name"), phone: val("phone"), email: val("email"), specialization: val("specialization"), employmentType: val("employmentType"), hiredAt: val("hiredAt"), maxWeeklyHours: Number(val("maxWeeklyHours") || 40), note: val("note"), accessEnabled: isChecked("accessEnabled"), username: val("teacherUsername"), password: val("teacherPassword") },
    student: { name: val("name"), groupId: val("groupId"), parentName: val("parentName"), parentRelationship: val("parentRelationship"), phone: val("phone"), parentEmail: val("parentEmail"), studentPhone: val("studentPhone"), email: val("email"), birthDate: val("birthDate"), gender: val("gender"), address: val("address"), source: val("source"), enrollmentDate: val("enrollmentDate"), note: val("note"), ...(isEdit ? { status: val("status"), transferReason: val("transferReason") } : { debt: Number(val("debt")) }) },
    group: { name: val("name"), subject: val("subject"), description: val("groupDescription"), level: val("level"), teacherId: val("teacherId"), room: val("room"), capacity: Number(val("capacity") || 0), monthlyFee: Number(val("monthlyFee") || 0), startDate: val("groupStartDate"), endDate: val("groupEndDate"), status: val("groupStatus"), color: val("groupColor"), note: val("groupNote") },
    lesson: {
      groupId: val("groupId"),
      time: lessonTimeValue(),
      date: val("lessonDate"),
      teacherId: val("lessonTeacherId"),
      roomName: val("lessonRoomName"),
      topic: val("lessonTopic"),
      homework: val("lessonHomework"),
      note: val("lessonNote"),
      ...(isEdit ? { reason: val("lessonChangeReason"), version: modalEntity()?.version } : {}),
    },
    payment: { studentId: val("studentId"), amount: Number(val("amount")), type: val("type"), ...(!isEdit ? { idempotencyKey: state.modal.idempotencyKey || createIdempotencyKey() } : {}) },
    message: { to: val("to"), student_id: state.selectedMessageStudentId || "", text: val("text") },
    lead: { name: val("name"), phone: val("phone"), source: val("source"), status: val("status"), note: val("note") },
  };
  const body = basePayloads[type];
  const collection = type === "teacher" ? "teachers" : type === "student" ? "students" : type === "group" ? "groups" : type === "lesson" ? "lessons" : type === "payment" ? "payments" : "";
  const path = isEdit && collection ? `/api/${collection}/${encodeURIComponent(state.modal.id)}` : {
    teacher: "/api/teachers",
    student: "/api/students",
    group: "/api/groups",
    lesson: "/api/lessons",
    payment: "/api/payments",
    message: "/api/messages",
    lead: "/api/leads",
  }[type];
  if (!path) return;
  state.isSaving = true;
  render();
  try {
    const saved = await api(path, { method: isEdit ? "PUT" : "POST", body: JSON.stringify(body) });
    if (isEdit) syncUpdatedEntity(type, saved);
    else syncCreatedEntity(type, saved, body);
    state.isSaving = false;
    state.modal = null;
    state.currentLesson = null;
    state.attendanceStudents = [];
    resetMessageModalState();
    showToast(tr("saved"));
    backgroundRefresh(mutationRefreshKeys(type), true);
    render();
  } catch (error) {
    state.isSaving = false;
    showToast(errorMessage(error));
    render();
  }
}

