async function savePassword(event) {
  event.preventDefault();
  if (state.passwordSaving) return;
  const currentPassword = val("currentPassword");
  const newPassword = val("newPassword");
  const confirmPassword = val("confirmPassword");
  if (newPassword !== confirmPassword) {
    showToast(tr("passwordMismatch"));
    return;
  }
  state.passwordSaving = true;
  render();
  try {
    await api("/api/settings/password", {
      method: "POST",
      body: JSON.stringify({ currentPassword, newPassword }),
    });
    state.passwordSaving = false;
    showToast(tr("passwordChanged"));
    render();
    setTimeout(() => logout(), 900);
  } catch (error) {
    state.passwordSaving = false;
    showToast(errorMessage(error));
    render();
  }
}

function toggleTelegramTestForm() {
  state.telegramTestForm = !state.telegramTestForm;
  render();
}

async function sendTelegramTest(event) {
  event.preventDefault();
  if (state.telegramTestSending) return;
  state.telegramTestSending = true;
  render();
  try {
    const result = await api("/api/telegram/test", {
      method: "POST",
      body: JSON.stringify({ chat_id: val("telegramTestChatId") }),
    });
    if (result.success) state.telegramTestForm = false;
    showToast(result.success ? tr("telegramTestSent") : result.error || tr("telegramTestFailed"));
  } catch (error) {
    showToast(errorMessage(error));
  } finally {
    state.telegramTestSending = false;
    render();
  }
}

function closeModal(event) {
  if (event.target.classList.contains("modal-backdrop")) closeAppModal();
}

async function login(event) {
  event.preventDefault();
  if (state.loginSaving) return;
  const username = val("loginUsername");
  const password = val("loginPassword");
  state.loginSaving = true;
  render();
  try {
    const result = await api("/api/login", {
      method: "POST",
      body: JSON.stringify({
        username,
        password,
      }),
    });
    setUser(result.user);
    state.page = "dashboard";
    state.loginSaving = false;
    await load();
  } catch (error) {
    state.loginSaving = false;
    showToast(errorMessage(error));
    render();
  }
}

async function logout() {
  await api("/api/logout", { method: "POST", body: "{}" }).catch(() => {});
  state.user = null;
  state.role = null;
  state.userId = null;
  state.data = null;
  state.drawer = null;
  state.groupDrawer = null;
  state.teacherDrawer = null;
  state.teacherSelfProfile = null;
  state.teacherSelfProfileLoading = false;
  state.teacherSelfProfileLoaded = false;
  state.modal = null;
  state.deleteConfirm = null;
  state.currentLesson = null;
  state.attendanceStudents = [];
  state.attendanceAlertConfirm = null;
  state.attendanceAlertSending = false;
  state.isSaving = false;
  state.tableSearch = {};
  state.tableSort = {};
  state.commandSearch = "";
  state.commandActiveIndex = 0;
  state.commandLoading = false;
  state.commandPaletteOpen = false;
  state.stageModal = null;
  state.stageMenu = null;
  state.taskModal = null;
  state.subscriptionModal = null;
  state.importModal = null;
  state.leadConvertModal = null;
  state.pipelineStages = [];
  currentStages = [];
  state.pipelineStagesLoaded = false;
  state.pipelineStagesLoading = false;
  state.lazyLoaded = {};
  state.lazyLoading = {};
  Object.keys(lazyPromises).forEach((key) => delete lazyPromises[key]);
  state.telegramTestForm = false;
  state.telegramTestSending = false;
  state.settingsSaving = false;
  state.centerSettingsSaving = false;
  state.passwordSaving = false;
  state.queueProcessing = false;
  state.quickLeadSaving = false;
  state.leadStageSaving = "";
  state.footerMenuOpen = false;
  state.platformTenants = [];
  state.platformLoading = false;
  state.platformSaving = false;
  state.platformModal = null;
  state.platformCreatedAdmins = {};
  state.page = "dashboard";
  render();
  if (typeof window !== "undefined" && window.location) window.location.reload();
}

function loginPage() {
  return `
    <main class="login-page">
      <form class="login-card" onsubmit="login(event)">
        ${loginLogo()}
        <h1>${html(tr("login"))}</h1>
        <div class="field"><label>${html(tr("username"))}</label><input id="loginUsername" autocomplete="username" placeholder="${attr(tr("username"))}" /></div>
        <div class="field"><label>${html(tr("password"))}</label><input id="loginPassword" type="password" autocomplete="current-password" placeholder="${attr(tr("password"))}" /></div>
        <button class="primary-button login-submit" type="submit" ${state.loginSaving ? "disabled" : ""}>${html(state.loginSaving ? tr("saving") : tr("login"))}</button>
        <div class="card-subtitle">${tr("demoLoginHelp")}</div>
      </form>
      ${state.toast ? `<div class="toast">${html(state.toast)}</div>` : ""}
    </main>
  `;
}

function render() {
  syncDocumentLanguage();
  syncBodyOverflow();
  if (!state.user) {
    app.innerHTML = loginPage();
    return;
  }
  if (isPlatformMode()) {
    app.innerHTML = platformShell();
    return;
  }
  app.innerHTML = `
    <div class="layout">
      ${sidebar()}
      ${state.mobileNav ? `<button class="mobile-nav-backdrop" aria-label="${attr(tr("closeMenu"))}" onclick="setState({ mobileNav: false })"></button>` : ""}
      <main class="main"><div class="content-container">${topbar()}${tenantModeBanner()}<div class="content-area">${page()}</div></div></main>
    </div>
    ${modal()}
    ${platformModal()}
    ${attendanceAlertModal()}
    ${stageModal()}
    ${deleteConfirmModal()}
    ${studentDrawer()}
    ${groupDrawer()}
    ${teacherDrawer()}
    ${commandPalette()}
    ${taskModal()}
    ${subscriptionModal()}
    ${importStudentsModal()}
    ${leadConversionModal()}
    ${state.toast ? `<div class="toast">${html(state.toast)}</div>` : ""}
  `;
  if (state.page === "lessons") {
    const scheduleFrame = typeof requestAnimationFrame === "function" ? requestAnimationFrame : (callback) => setTimeout(callback, 0);
    scheduleFrame(() => updateCalendarWidth(true));
  }
}

function toggleLang() {
  setLanguage(state.lang === "uz" ? "ru" : "uz");
  state.footerMenuOpen = false;
  render();
}

function toggleFooterMenu(event) {
  if (event?.stopPropagation) event.stopPropagation();
  state.footerMenuOpen = !state.footerMenuOpen;
  state.stageMenu = null;
  state.calendarPopover = null;
  render();
}

function navigateTo(page) {
  state.footerMenuOpen = false;
  state.stageMenu = null;
  state.calendarPopover = null;
  setState({ page, mobileNav: false });
}

async function navigateAccount(section) {
  state.footerMenuOpen = false;
  state.stageMenu = null;
  state.calendarPopover = null;
  state.page = "settings";
  state.mobileNav = false;
  render();
  if (state.role === "teacher") {
    await loadDataKeys(["teachers", "lessons", "students"]).catch(() => {});
  }
  setTimeout(() => {
    const targetId = section === "security" ? "securitySettings" : "profileSettings";
    const target = document.getElementById(targetId);
    if (!target) return;
    if (typeof target.scrollIntoView === "function") target.scrollIntoView({ behavior: "smooth", block: "start" });
    const focusTarget = section === "security" ? document.getElementById("currentPassword") : target.querySelector("input");
    if (focusTarget && typeof focusTarget.focus === "function") focusTarget.focus();
  }, 0);
}

if (typeof document !== "undefined" && document.addEventListener) {
  document.addEventListener("keydown", (event) => {
    if ((event.metaKey || event.ctrlKey) && event.key.toLowerCase() === "k") {
      event.preventDefault();
      openCommandPalette();
      return;
    }
    if (event.key === "Escape") closeAllTransientUi();
  });
  document.addEventListener("click", (event) => {
    let changed = false;
    if (state.footerMenuOpen && !event.target.closest(".footer-menu-dropdown") && !event.target.closest(".sidebar-account-trigger")) {
      state.footerMenuOpen = false;
      changed = true;
    }
    if (state.messageStudentDropdown && !event.target.closest(".message-recipient-field")) {
      state.messageStudentDropdown = false;
      changed = true;
    }
    if (state.stageMenu && !event.target.closest(".stage-dropdown") && !event.target.closest(".kanban-menu-button")) {
      state.stageMenu = null;
      changed = true;
    }
    if (state.calendarPopover && !event.target.closest(".lesson-popover") && !event.target.closest(".calendar-lesson")) {
      state.calendarPopover = null;
      changed = true;
    }
    if (changed) render();
  });
}

if (typeof window !== "undefined" && window.addEventListener) {
  window.addEventListener("resize", () => {
    if (state.page === "lessons") updateCalendarWidth(true);
  });
}

checkAuth();
